import React from 'react';
import { List, ChevronLeft, ChevronRight } from 'lucide-react';
import { INVENTORY_DATA } from '../constants';

const InventoryTable: React.FC = () => {
  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h2 className="text-xl font-bold flex items-center gap-2 text-slate-900 dark:text-white">
          <List size={24} className="text-slate-400" />
          Inventory Overview
        </h2>
        <div className="flex gap-2">
          <button className="bg-slate-100 dark:bg-slate-800 text-xs font-semibold px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors dark:text-slate-300">
            Filter
          </button>
          <button className="bg-slate-100 dark:bg-slate-800 text-xs font-semibold px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors dark:text-slate-300">
            Export CSV
          </button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider">Item Name</th>
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider">Category</th>
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider">Stock Level</th>
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider">Unit</th>
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200 dark:divide-slate-800">
              {INVENTORY_DATA.map((item) => {
                const stockPercent = Math.min((item.stockLevel / item.maxStock) * 100, 100);
                let barColor = 'bg-emerald-500';
                if (stockPercent < 20) barColor = 'bg-safety-orange';
                if (item.stockLevel === 0) barColor = 'bg-slate-300 dark:bg-slate-600';

                let categoryColor = 'bg-slate-100 text-slate-700 dark:bg-slate-800 dark:text-slate-300';
                if (item.category === 'TOOLS') categoryColor = 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400';
                if (item.category === 'MATERIALS') categoryColor = 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400';
                if (item.category === 'PPE') categoryColor = 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400';

                let statusColor = 'text-emerald-500';
                if (item.status === 'Low Stock') statusColor = 'text-safety-orange';
                if (item.status === 'Out of Stock') statusColor = 'text-red-500';

                return (
                  <tr key={item.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors group">
                    <td className="px-4 py-3">
                      <div className="font-medium text-sm text-slate-900 dark:text-slate-100">{item.name}</div>
                      <div className="text-[10px] text-slate-500">ID: {item.sku}</div>
                    </td>
                    <td className="px-4 py-3">
                      <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wide ${categoryColor}`}>
                        {item.category}
                      </span>
                    </td>
                    <td className="px-4 py-3">
                      <div className="flex items-center gap-3">
                        <div className="w-20 h-1.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                          <div className={`h-full rounded-full ${barColor}`} style={{ width: `${stockPercent}%` }}></div>
                        </div>
                        <span className="text-xs font-medium text-slate-700 dark:text-slate-300 tabular-nums">{item.stockLevel}</span>
                      </div>
                    </td>
                    <td className="px-4 py-3 text-sm text-slate-500">{item.unit}</td>
                    <td className="px-4 py-3">
                      <span className={`flex items-center gap-1.5 text-xs font-medium ${statusColor}`}>
                        <span className={`size-1.5 rounded-full ${statusColor.replace('text-', 'bg-')}`}></span>
                        {item.status}
                      </span>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>

        {/* Pagination Footer */}
        <div className="px-4 py-3 border-t border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/30 flex items-center justify-between">
          <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">Showing 1-12 of 248 items</p>
          <div className="flex gap-1">
            <button className="size-8 flex items-center justify-center rounded border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-500 transition-colors">
              <ChevronLeft size={16} />
            </button>
            <button className="size-8 flex items-center justify-center rounded border border-slate-200 dark:border-slate-700 bg-primary text-white shadow-sm">
              <span className="text-xs font-bold">1</span>
            </button>
            <button className="size-8 flex items-center justify-center rounded border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-300 transition-colors">
              <span className="text-xs font-bold">2</span>
            </button>
            <button className="size-8 flex items-center justify-center rounded border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-500 transition-colors">
              <ChevronRight size={16} />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

