                        <th className="pb-2 text-black">Item</th>
                        <th className="pb-2 text-right text-black">Qty</th>
                        <th className="pb-2 text-right text-black">Price</th>
                    </tr>
                </thead>
                <tbody>
                    <tr>
                        <td className="py-1 pr-2">
                            <div className="font-bold text-black">{data.itemName}</div>
                            <div className="text-[10px] text-slate-500">@ {data.unitPrice.toFixed(2)}</div>
                        </td>
                        <td className="py-1 text-right align-top text-black">{data.quantity}</td>
                        <td className="py-1 text-right align-top font-bold text-black">{(data.unitPrice * data.quantity).toFixed(2)}</td>
                    </tr>
                </tbody>
            </table>

            <div className="border-t-2 border-dashed border-slate-300 pt-4 space-y-1 text-black">
                <div className="flex justify-between items-end">
                    <span className="text-sm font-bold">TOTAL</span>
                    <span className="text-xl font-black">${data.totalPrice.toFixed(2)}</span>
                </div>
            </div>

            <div className="bg-slate-100 rounded p-3 mt-6 text-xs text-black">
                <div className="flex justify-between mb-1">
                    <span className="text-slate-500">Method:</span>
                    <span className="font-bold">{data.paymentMethod}</span>
                </div>
                {data.paymentMethod === 'MPESA' && (
                     <div className="flex justify-between">
                        <span className="text-slate-500">Ref Code:</span>
                        <span className="font-bold font-mono">{data.mpesaCode}</span>
                    </div>
                )}
            </div>

            <div className="text-center mt-8 space-y-2">
                <p className="text-[10px] text-slate-400 uppercase">Thank you for your business!</p>
                {/* Removed dark mode background classes from barcode to maintain receipt look */}
                <div className="w-full h-8 bg-slate-200 flex items-center justify-center gap-1 opacity-50">
                    {/* Fake Barcode */}
                    {[...Array(20)].map((_, i) => (
                        <div key={i} className="h-full bg-slate-900" style={{ width: Math.random() > 0.5 ? '2px' : '4px' }}></div>
                    ))}
                </div>
            </div>
        </div>

        {/* Footer Actions (Screen Only) */}
        <div className="p-4 bg-slate-50 border-t border-slate-100 flex gap-3 print:hidden">
            <button 
                onClick={onClose}
                className="flex-1 py-2.5 text-sm font-bold text-slate-600 hover:text-slate-800 hover:bg-slate-200/50 rounded-lg transition-colors"
            >
                Close
            </button>
            <button 
                onClick={handlePrint}
                className="flex-1 py-2.5 text-sm font-bold bg-slate-900 text-white hover:bg-slate-800 rounded-lg shadow-lg shadow-slate-900/20 flex items-center justify-center gap-2 transition-all active:scale-95"
            >
                <Printer size={16} />
                Print Receipt
            </button>
        </div>
      </div>

      {/* Print Styles */}
      <style>{`
        @media print {
            body * {
                visibility: hidden;
            }
            #printable-receipt, #printable-receipt * {
                visibility: visible;
            }
            #printable-receipt {
                position: absolute;
                left: 0;
                top: 0;
                width: 100%;
                margin: 0;
                padding: 20px;
            }
        }
      `}</style>
    </div>
  );
};

export default ReceiptModal;

import React, { useState, useEffect } from 'react';
import { X, Save, FileText, User, Car, Clock, Eye, Layers, Package, Wrench, HardHat, DollarSign, Receipt, CreditCard, Banknote, Smartphone } from 'lucide-react';
import { InventoryItem } from '../types';

interface ActionModalProps {
  isOpen: boolean;
  onClose: () => void;
  // Updated signature to accept metadata
  onSubmit: (itemId: string, quantity: number, notes: string, meta?: any) => void;
  type: 'DELIVERY' | 'SALE' | 'RETURN' | null;
  inventory: InventoryItem[];
}

const ActionModal: React.FC<ActionModalProps> = ({ isOpen, onClose, onSubmit, type, inventory }) => {
  const [selectedItemId, setSelectedItemId] = useState('');
  const [quantity, setQuantity] = useState(1);
  const [notes, setNotes] = useState('');

  // Category Filter State
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  // Delivery specific fields
  const [poNumber, setPoNumber] = useState('');
  const [driverName, setDriverName] = useState('');
  const [plateNumber, setPlateNumber] = useState('');
  const [timeReceived, setTimeReceived] = useState('');

  // Sale specific fields
  const [customerName, setCustomerName] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'MPESA'>('CASH');
  const [mpesaCode, setMpesaCode] = useState('');

  // Filter inventory based on category
  const filteredInventory = inventory.filter(item => 
    activeCategory === 'ALL' ? true : item.category === activeCategory
  );

  // Find selected item object for details, defaulting to first available if selection is empty/invalid
  const selectedItem = inventory.find(i => i.id === selectedItemId) || filteredInventory[0];

  // Calculate totals
  const totalCost = selectedItem ? selectedItem.price * quantity : 0;

  // Reset form when modal opens
  useEffect(() => {
    if (isOpen) {
      setActiveCategory('ALL');
      // Set initial selected item from the full inventory
      const initialItem = inventory[0];
      setSelectedItemId(initialItem?.id || '');
      setQuantity(1);
      setNotes('');
      setPoNumber('');
      setDriverName('');
      setPlateNumber('');
      setCustomerName('');
      setPaymentMethod('CASH');
      setMpesaCode('');

      const now = new Date();
      setTimeReceived(`${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`);
    }
  }, [isOpen, inventory]);

  const handleCategoryChange = (category: string) => {
    setActiveCategory(category);
    // Auto-select first item of new category to prevent dead selection
    const firstItem = inventory.find(item => 
        category === 'ALL' ? true : item.category === category
    );
    if (firstItem) {
        setSelectedItemId(firstItem.id);
    } else {
        setSelectedItemId('');
    }
  };

  // Calculate preview text
  const getPreviewText = () => {
    if (type === 'DELIVERY') {
        const details = [
            selectedItem && `Item: ${selectedItem.name}`,
            selectedItem && `Category: ${selectedItem.category}`,
            poNumber && `PO: ${poNumber}`,
            driverName && `Driver: ${driverName}`,
            plateNumber && `Plate: ${plateNumber}`,
            timeReceived && `Time: ${timeReceived}`
        ].filter(Boolean).join(' • ');
        return notes ? `${details} \nNote: ${notes}` : details;
    } else if (type === 'SALE') {
        const paymentDetails = paymentMethod === 'CASH' ? 'Cash' : `M-Pesa: ${mpesaCode}`;
        const details = [
            selectedItem && `Item: ${selectedItem.name} (x${quantity})`,
            customerName && `Customer: ${customerName}`,
            `Payment: ${paymentDetails}`,
            `Total: $${totalCost.toFixed(2)}`
        ].filter(Boolean).join(' • ');
        return notes ? `${details} \nNote: ${notes}` : details;
    }
    return notes;
  };

  const previewText = getPreviewText();

  if (!isOpen || !type) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Validate M-Pesa Code
    if (type === 'SALE' && paymentMethod === 'MPESA' && !mpesaCode.trim()) {
        return; 
    }

    // Ensure we have a valid ID. If selectedItemId is empty, use the fallback selectedItem's ID
    const finalItemId = selectedItemId || selectedItem?.id;
    if (!finalItemId) return;

    let submissionNotes = notes;
    let metaData: any = {};

    // Append standard details to notes for the log
    if (type === 'DELIVERY') {
      submissionNotes = getPreviewText();
    } else if (type === 'SALE') {
      const paymentDetails = paymentMethod === 'CASH' ? 'Cash' : `M-Pesa: ${mpesaCode}`;
      submissionNotes = `${customerName ? `Cust: ${customerName}` : 'Walk-in'} • ${paymentDetails} • Total: $${totalCost.toFixed(2)} ${notes ? `• ${notes}` : ''}`;

      // Pass structured data for receipt generation
      metaData = {
        customerName,
        paymentMethod,
        mpesaCode,
        totalPrice: totalCost,
        unitPrice: selectedItem?.price || 0
      };
    }

    onSubmit(finalItemId, quantity, submissionNotes, metaData);
    onClose();
  };

  const getTitle = () => {
    switch(type) {
      case 'DELIVERY': return 'Log Incoming Delivery';
      case 'SALE': return 'Record New Sale';
      case 'RETURN': return 'Log Customer Return';
      default: return '';
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 rounded-xl w-full max-w-md shadow-2xl border border-slate-200 dark:border-slate-800 scale-100 animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto">
        <div className="flex items-center justify-between p-6 border-b border-slate-100 dark:border-slate-800 sticky top-0 bg-white dark:bg-slate-900 z-10">
          <h3 className="text-lg font-bold text-slate-900 dark:text-white">{getTitle()}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-500 dark:hover:text-slate-300">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4">

          {/* Category Selector */}
          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">Filter Category</label>
            <div className="flex p-1 bg-slate-100 dark:bg-slate-800 rounded-lg gap-1">
                {[
                  { id: 'ALL', icon: Layers, label: 'All' },
                  { id: 'TOOLS', icon: Wrench, label: 'Tools' },
                  { id: 'MATERIALS', icon: Package, label: 'Materials' },
                  { id: 'PPE', icon: HardHat, label: 'PPE' }
                ].map((cat) => (
                  <button
                    key={cat.id}
                    type="button"
                    onClick={() => handleCategoryChange(cat.id)}
                    className={`flex-1 flex items-center justify-center gap-1.5 py-2 text-[10px] font-bold uppercase rounded-md transition-all ${
                      activeCategory === cat.id
                        ? 'bg-white dark:bg-slate-700 text-primary shadow-sm ring-1 ring-slate-200 dark:ring-slate-600'
                        : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 hover:bg-slate-200/50 dark:hover:bg-slate-700/50'
                    }`}
                  >
                    <cat.icon size={12} />
                    <span className="hidden sm:inline">{cat.label}</span>
                  </button>
                ))}
            </div>
          </div>

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">
                Select Item {activeCategory !== 'ALL' && <span className="text-primary">({activeCategory})</span>}
            </label>
            <select 
              value={selectedItemId || selectedItem?.id || ''}
              onChange={(e) => setSelectedItemId(e.target.value)}
              className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
            >
              {filteredInventory.length > 0 ? (
                  filteredInventory.map(item => (
                    <option key={item.id} value={item.id}>
                      {item.name} [${item.price.toFixed(2)}] (Stock: {item.stockLevel})
                    </option>
                  ))
              ) : (
                  <option disabled>No items found in this category</option>
              )}
            </select>
          </div>

          <div className="flex gap-4">
             <div className="flex-1">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">Quantity</label>
                <input 
                  type="number" 
                  min="1"
                  value={quantity}
                  onChange={(e) => setQuantity(parseInt(e.target.value))}
                  className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                />
             </div>
             {type === 'DELIVERY' && (
                <div className="flex-1">
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <Clock size={12} /> Time Received
                    </label>
                    <input 
                      type="time" 
                      value={timeReceived}
                      onChange={(e) => setTimeReceived(e.target.value)}
                      className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                    />
                </div>
             )}
             {type === 'SALE' && (
                <div className="flex-1">
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <DollarSign size={12} /> Total Price
                    </label>
                    <div className="w-full px-3 py-2 rounded-lg border border-slate-200 dark:border-slate-700 bg-slate-100 dark:bg-slate-800 text-slate-900 dark:text-white text-sm font-bold flex items-center">
                        ${totalCost.toFixed(2)}
                    </div>
                </div>
             )}
          </div>

          {type === 'SALE' && (
            <div className="space-y-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-lg border border-slate-200 dark:border-slate-700">
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <User size={12} /> Customer Name (Optional)
                    </label>
                    <input 
                      type="text" 
                      placeholder="e.g. Walk-in or Company Name"
                      value={customerName}
                      onChange={(e) => setCustomerName(e.target.value)}
                      className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                    />
                 </div>

                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <CreditCard size={12} /> Payment Method <span className="text-red-500">*</span>
                    </label>
                    <div className="flex gap-2">
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('CASH')}
                            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg border text-sm font-bold transition-all ${
                                paymentMethod === 'CASH' 
                                ? 'bg-emerald-500 text-white border-emerald-600 shadow-sm' 
                                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700'
                            }`}
                        >
                            <Banknote size={16} />
                            Cash
                        </button>
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('MPESA')}
                            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg border text-sm font-bold transition-all ${
                                paymentMethod === 'MPESA' 
                                ? 'bg-emerald-500 text-white border-emerald-600 shadow-sm' 
                                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700'
                            }`}
                        >
                            <Smartphone size={16} />
                            M-Pesa
                        </button>
                    </div>
                 </div>

                 {paymentMethod === 'MPESA' && (
                     <div className="animate-in fade-in slide-in-from-top-1 duration-200">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Receipt size={12} /> Transaction Code <span className="text-red-500">*</span>
                        </label>
                        <input 
                          type="text" 
                          required={paymentMethod === 'MPESA'}
                          placeholder="e.g. QEH83729"
                          value={mpesaCode}
                          onChange={(e) => setMpesaCode(e.target.value.toUpperCase())}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm uppercase font-mono"
                        />
                     </div>
                 )}
            </div>
          )}

          {type === 'DELIVERY' && (
            <div className="space-y-4 p-4 bg-slate-50 dark:bg-slate-800/50 rounded-lg border border-slate-200 dark:border-slate-700">
                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <FileText size={12} /> Purchase Order #
                    </label>
                    <input 
                      type="text" 
                      placeholder="e.g. PO-2023-001"
                      value={poNumber}
                      onChange={(e) => setPoNumber(e.target.value)}
                      className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                    />
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <User size={12} /> Driver Name
                        </label>
                        <input 
                          type="text" 
                          placeholder="John Doe"
                          value={driverName}
                          onChange={(e) => setDriverName(e.target.value)}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Car size={12} /> Plate Number
                        </label>
                        <input 
                          type="text" 
                          placeholder="ABC 1234"
                          value={plateNumber}
                          onChange={(e) => setPlateNumber(e.target.value)}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                </div>
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">
                {type === 'DELIVERY' ? 'Additional Notes' : 'Notes / Remarks'}
            </label>
            <textarea 
              rows={3}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder={type === 'SALE' ? "Additional sale info..." : type === 'RETURN' ? "e.g., Damaged item" : "Optional notes..."}
              className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
            ></textarea>
          </div>

          {/* Log/Receipt Preview Section */}
          {(type === 'DELIVERY' || type === 'SALE') && previewText && (
            <div className="mt-2 p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 rounded-lg animate-in fade-in slide-in-from-top-2 duration-300">
               <div className="flex items-center gap-2 mb-1.5">
                 {type === 'SALE' ? <Receipt size={12} className="text-blue-500"/> : <Eye size={12} className="text-blue-500" />}
                 <p className="text-[10px] font-bold text-blue-500 uppercase tracking-wide">
                    {type === 'SALE' ? 'Sale Summary' : 'Log Preview'}
                 </p>
               </div>
               <div className="text-sm text-slate-900 dark:text-slate-100 font-mono whitespace-pre-wrap pl-5 border-l-2 border-blue-200 dark:border-blue-800">
                 {previewText}
               </div>
            </div>
          )}

          <div className="flex justify-end gap-3 pt-4 border-t border-slate-100 dark:border-slate-800 mt-2">
            <button 
              type="button" 
              onClick={onClose}
              className="px-4 py-2 text-sm font-medium text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors"
            >
              Cancel
            </button>
            <button 
              type="submit"
              className="flex items-center gap-2 px-4 py-2 bg-primary text-white rounded-lg text-sm font-bold hover:bg-primary-dark transition-colors shadow-lg shadow-primary/20"
            >
              <Save size={16} />
              Confirm {type === 'SALE' ? 'Sale' : 'Action'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default ActionModal;

