import React, { useState } from 'react';
import { List, ChevronLeft, ChevronRight, Download, Filter } from 'lucide-react';
import { InventoryItem } from '../types';

interface InventoryTableProps {
  data: InventoryItem[];
  filterActive: boolean;
  onFilterToggle: () => void;
}

const ITEMS_PER_PAGE = 5;

const InventoryTable: React.FC<InventoryTableProps> = ({ data, filterActive, onFilterToggle }) => {
  const [currentPage, setCurrentPage] = useState(1);
  const totalPages = Math.ceil(data.length / ITEMS_PER_PAGE);

  // Calculate displayed data
  const startIndex = (currentPage - 1) * ITEMS_PER_PAGE;
  const currentData = data.slice(startIndex, startIndex + ITEMS_PER_PAGE);

  const handleExportCSV = () => {
    const headers = ['Name', 'SKU', 'Category', 'Stock Level', 'Unit', 'Status', 'Buying Price', 'Selling Price'];
    const csvContent = [
      headers.join(','),
      ...data.map(item => 
        `"${item.name}","${item.sku}","${item.category}",${item.stockLevel},"${item.unit}","${item.status}",${item.buyingPrice},${item.sellingPrice}`
      )
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = 'inventory_export.csv';
    link.click();
  };

  const handlePageChange = (newPage: number) => {
    if (newPage >= 1 && newPage <= totalPages) {
      setCurrentPage(newPage);
    }
  };

  // Helper to format currency
  const formatKsh = (amount: number) => {
    return `Ksh ${amount.toLocaleString()}`;
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <h2 className="text-xl font-bold flex items-center gap-2 text-slate-900 dark:text-white">
          <List size={24} className="text-slate-400" />
          Inventory Overview
        </h2>
        <div className="flex gap-2">
          <button 
            onClick={onFilterToggle}
            className={`flex-1 sm:flex-none flex items-center justify-center gap-2 text-xs font-semibold px-3 py-2 sm:py-1.5 rounded-lg border transition-colors ${
              filterActive 
                ? 'bg-primary text-white border-primary' 
                : 'bg-slate-100 dark:bg-slate-800 border-slate-200 dark:border-slate-700 hover:bg-slate-200 dark:hover:bg-slate-700 dark:text-slate-300'
            }`}
          >
            <Filter size={14} />
            {filterActive ? 'Low Stock Only' : 'Filter'}
          </button>
          <button 
            onClick={handleExportCSV}
            className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-slate-100 dark:bg-slate-800 text-xs font-semibold px-3 py-2 sm:py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 hover:bg-slate-200 dark:hover:bg-slate-700 transition-colors dark:text-slate-300"
          >
            <Download size={14} />
            Export CSV
          </button>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[600px] sm:min-w-0">
            <thead>
              <tr className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider">Item Name</th>
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider hidden md:table-cell">Category</th>
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider">Stock Level</th>
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider hidden sm:table-cell">Unit</th>
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider hidden sm:table-cell">Status</th>
                <th className="px-4 py-3 text-xs font-bold text-slate-500 uppercase tracking-wider text-right">Price</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200 dark:divide-slate-800">
              {currentData.length > 0 ? (
                currentData.map((item) => {
                  const stockPercent = Math.min((item.stockLevel / item.maxStock) * 100, 100);
                  let barColor = 'bg-emerald-500';
                  if (stockPercent < 20) barColor = 'bg-safety-orange';
                  if (item.stockLevel === 0) barColor = 'bg-slate-300 dark:bg-slate-600';

                  let categoryColor = 'bg-slate-100 text-slate-700 dark:bg-slate-800 dark:text-slate-300';
                  if (item.category === 'TOOLS') categoryColor = 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400';
                  if (item.category === 'MATERIALS') categoryColor = 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400';
                  if (item.category === 'PPE') categoryColor = 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400';

                  let statusColor = 'text-emerald-500';
                  if (item.status === 'Low Stock') statusColor = 'text-safety-orange';
                  if (item.status === 'Out of Stock') statusColor = 'text-red-500';

                  return (
                    <tr key={item.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/30 transition-colors group">
                      <td className="px-4 py-3">
                        <div className="font-medium text-sm text-slate-900 dark:text-slate-100">{item.name}</div>
                        <div className="text-[10px] text-slate-500">ID: {item.sku}</div>
                      </td>
                      <td className="px-4 py-3 hidden md:table-cell">
                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wide ${categoryColor}`}>
                          {item.category}
                        </span>
                      </td>
                      <td className="px-4 py-3">
                        <div className="flex items-center gap-3">
                          <div className="w-16 sm:w-20 h-1.5 bg-slate-100 dark:bg-slate-800 rounded-full overflow-hidden">
                            <div className={`h-full rounded-full ${barColor}`} style={{ width: `${stockPercent}%` }}></div>
                          </div>
                          <span className="text-xs font-medium text-slate-700 dark:text-slate-300 tabular-nums">{item.stockLevel}</span>
                        </div>
                      </td>
                      <td className="px-4 py-3 text-sm text-slate-500 hidden sm:table-cell">{item.unit}</td>
                      <td className="px-4 py-3 hidden sm:table-cell">
                        <span className={`flex items-center gap-1.5 text-xs font-medium ${statusColor}`}>
                          <span className={`size-1.5 rounded-full ${statusColor.replace('text-', 'bg-')}`}></span>
                          {item.status}
                        </span>
                      </td>
                      <td className="px-4 py-3 text-right">
                        <div className="font-bold text-sm text-slate-900 dark:text-white">{formatKsh(item.sellingPrice)}</div>
                      </td>
                    </tr>
                  );
                })
              ) : (
                <tr>
                  <td colSpan={6} className="px-4 py-8 text-center text-slate-500 text-sm">
                    No items found matching your criteria.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Pagination Footer */}
        {data.length > 0 && (
          <div className="px-4 py-3 border-t border-slate-200 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/30 flex items-center justify-between">
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest">
              Showing {startIndex + 1}-{Math.min(startIndex + ITEMS_PER_PAGE, data.length)} of {data.length} items
            </p>
            <div className="flex gap-1">
              <button 
                onClick={() => handlePageChange(currentPage - 1)}
                disabled={currentPage === 1}
                className="size-8 flex items-center justify-center rounded border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-500 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <ChevronLeft size={16} />
              </button>

              {/* Simple pagination: 1, 2, ... N */}
              {Array.from({ length: totalPages }, (_, i) => i + 1).map((page) => (
                 <button 
                  key={page}
                  onClick={() => handlePageChange(page)}
                  className={`size-8 flex items-center justify-center rounded border transition-colors ${
                    currentPage === page
                      ? 'bg-primary text-white border-primary'
                      : 'border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-500 dark:text-slate-300'
                  }`}
                >
                  <span className="text-xs font-bold">{page}</span>
                </button>
              ))}

              <button 
                onClick={() => handlePageChange(currentPage + 1)}
                disabled={currentPage === totalPages}
                className="size-8 flex items-center justify-center rounded border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 hover:bg-slate-50 dark:hover:bg-slate-700 text-slate-500 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <ChevronRight size={16} />
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default InventoryTable;

import React, { useState, useEffect } from 'react';
import { X, Save, FileText, User, Car, Clock, Eye, Layers, Package, Wrench, HardHat, DollarSign, Receipt, CreditCard, Banknote, Smartphone, Plus, Trash2 } from 'lucide-react';
import { InventoryItem } from '../types';

interface ActionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (items: { itemId: string; quantity: number; price: number }[], notes: string, meta?: any) => void;
  type: 'DELIVERY' | 'SALE' | 'RETURN' | null;
  inventory: InventoryItem[];
}

interface CartItem {
  itemId: string;
  quantity: number;
  price: number;
}

const ActionModal: React.FC<ActionModalProps> = ({ isOpen, onClose, onSubmit, type, inventory }) => {
  // State for multiple items
  const [cartItems, setCartItems] = useState<CartItem[]>([{ itemId: '', quantity: 1, price: 0 }]);

  const [notes, setNotes] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  // Delivery specific fields
  const [poNumber, setPoNumber] = useState('');
  const [driverName, setDriverName] = useState('');
  const [plateNumber, setPlateNumber] = useState('');
  const [timeReceived, setTimeReceived] = useState('');

  // Sale specific fields
  const [customerName, setCustomerName] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'MPESA'>('CASH');
  const [mpesaCode, setMpesaCode] = useState('');

  // Filter inventory for the dropdowns
  const filteredInventory = inventory.filter(item => 
    activeCategory === 'ALL' ? true : item.category === activeCategory
  );

  // Helper to format currency
  const formatKsh = (amount: number) => {
    return `Ksh ${amount.toLocaleString()}`;
  };

  // Helper to get active price based on transaction type
  const getTransactionPrice = (item: InventoryItem) => {
    if (type === 'DELIVERY') return item.buyingPrice;
    return item.sellingPrice; // SALE or RETURN
  };

  // Calculate Totals
  const calculateTotal = () => {
    return cartItems.reduce((sum, cartItem) => {
      return sum + (cartItem.price * cartItem.quantity);
    }, 0);
  };

  const grandTotal = calculateTotal();

  // Reset form when modal opens
  useEffect(() => {
    if (isOpen) {
      setActiveCategory('ALL');

      // Initialize with first available item and its price
      const defaultItem = inventory[0];
      const defaultPrice = defaultItem ? getTransactionPrice(defaultItem) : 0;

      setCartItems([{ 
        itemId: defaultItem?.id || '', 
        quantity: 1, 
        price: defaultPrice 
      }]);

      setNotes('');
      setPoNumber('');
      setDriverName('');
      setPlateNumber('');
      setCustomerName('');
      setPaymentMethod('CASH');
      setMpesaCode('');

      const now = new Date();
      setTimeReceived(`${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`);
    }
  }, [isOpen, inventory, type]);

  // --- Item Management Handlers ---

  const handleAddItem = () => {
    // Add new row with first available item in current filter
    const defaultItem = filteredInventory[0] || inventory[0];
    const defaultId = defaultItem?.id || '';
    const defaultPrice = defaultItem ? getTransactionPrice(defaultItem) : 0;

    setCartItems([...cartItems, { itemId: defaultId, quantity: 1, price: defaultPrice }]);
  };

  const handleRemoveItem = (index: number) => {
    if (cartItems.length > 1) {
      const newItems = [...cartItems];
      newItems.splice(index, 1);
      setCartItems(newItems);
    }
  };

  const handleItemChange = (index: number, field: keyof CartItem, value: string | number) => {
    const newItems = [...cartItems];

    if (field === 'itemId') {
      // When item changes, also update the price default
      const item = inventory.find(i => i.id === value);
      const newPrice = item ? getTransactionPrice(item) : 0;
      newItems[index] = { 
        ...newItems[index], 
        itemId: String(value), 
        price: newPrice 
      };
    } else {
      newItems[index] = { ...newItems[index], [field]: value };
    }

    setCartItems(newItems);
  };

  // --- Preview Logic ---

  const getPreviewText = () => {
    const itemCount = cartItems.length;
    const itemSummary = cartItems.map(c => {
        const i = inventory.find(inv => inv.id === c.itemId);
        // Show overridden price in summary if needed, but for brevity just name/qty
        return i ? `${i.name} (x${c.quantity})` : 'Unknown';
    }).join(', ');

    if (type === 'DELIVERY') {
        const details = [
            `Items (${itemCount}): ${itemSummary}`,
            poNumber && `PO: ${poNumber}`,
            driverName && `Driver: ${driverName}`,
            plateNumber && `Plate: ${plateNumber}`,
            timeReceived && `Time: ${timeReceived}`,
            `Total Cost: ${formatKsh(grandTotal)}`
        ].filter(Boolean).join(' • ');
        return notes ? `${details} \nNote: ${notes}` : details;
    } else if (type === 'SALE') {
        const paymentDetails = paymentMethod === 'CASH' ? 'Cash' : `M-Pesa: ${mpesaCode}`;
        const details = [
            `Items: ${itemSummary}`,
            customerName && `Customer: ${customerName}`,
            `Payment: ${paymentDetails}`,
            `Total: ${formatKsh(grandTotal)}`
        ].filter(Boolean).join(' • ');
        return notes ? `${details} \nNote: ${notes}` : details;
    }
    return notes;
  };

  const previewText = getPreviewText();

  if (!isOpen || !type) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Validate M-Pesa Code
    if (type === 'SALE' && paymentMethod === 'MPESA' && !mpesaCode.trim()) {
        return; 
    }

    // Filter out invalid items (empty IDs)
    const validItems = cartItems.filter(i => i.itemId);
    if (validItems.length === 0) return;

    let submissionNotes = notes;
    let metaData: any = {};

    if (type === 'DELIVERY') {
      submissionNotes = getPreviewText();
    } else if (type === 'SALE') {
      const paymentDetails = paymentMethod === 'CASH' ? 'Cash' : `M-Pesa: ${mpesaCode}`;
      submissionNotes = `${customerName ? `Cust: ${customerName}` : 'Walk-in'} • ${paymentDetails} • Total: ${formatKsh(grandTotal)}`;
      if (notes) submissionNotes += ` • ${notes}`;

      metaData = {
        customerName,
        paymentMethod,
        mpesaCode,
        totalPrice: grandTotal
      };
    }

    onSubmit(validItems, submissionNotes, metaData);
    onClose();
  };

  const getTitle = () => {
    switch(type) {
      case 'DELIVERY': return 'Log Incoming Delivery';
      case 'SALE': return 'Record New Sale';
      case 'RETURN': return 'Log Customer Return';
      default: return '';
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 rounded-xl w-full max-w-lg shadow-2xl border border-slate-200 dark:border-slate-800 scale-100 animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto flex flex-col m-4">
        <div className="flex items-center justify-between p-6 border-b border-slate-100 dark:border-slate-800 sticky top-0 bg-white dark:bg-slate-900 z-10 shrink-0">
          <h3 className="text-lg font-bold text-slate-900 dark:text-white">{getTitle()}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-500 dark:hover:text-slate-300">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4 flex-1 overflow-y-auto">

          {/* Category Filter */}
          <div className="sticky top-0 bg-white dark:bg-slate-900 z-10 pb-2">
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">Filter Item List</label>
            <div className="flex p-1 bg-slate-100 dark:bg-slate-800 rounded-lg gap-1">
                {[
                  { id: 'ALL', icon: Layers, label: 'All' },
                  { id: 'TOOLS', icon: Wrench, label: 'Tools' },
                  { id: 'MATERIALS', icon: Package, label: 'Materials' },
                  { id: 'PPE', icon: HardHat, label: 'PPE' }
                ].map((cat) => (
                  <button
                    key={cat.id}
                    type="button"
                    onClick={() => setActiveCategory(cat.id)}
                    className={`flex-1 flex items-center justify-center gap-1.5 py-2 text-[10px] font-bold uppercase rounded-md transition-all ${
                      activeCategory === cat.id
                        ? 'bg-white dark:bg-slate-700 text-primary shadow-sm ring-1 ring-slate-200 dark:ring-slate-600'
                        : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 hover:bg-slate-200/50 dark:hover:bg-slate-700/50'
                    }`}
                  >
                    <cat.icon size={12} />
                    <span className="hidden sm:inline">{cat.label}</span>
                  </button>
                ))}
            </div>
          </div>

          {/* Item List */}
          <div className="space-y-3">
             <div className="flex justify-between items-end">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide">
                    Items ({cartItems.length})
                </label>
             </div>

             {cartItems.map((cartItem, index) => {
                 return (
                    <div key={index} className="flex gap-2 items-start animate-in fade-in slide-in-from-left-2 duration-300">
                        <div className="flex-1">
                            <label className="text-[10px] text-slate-400 font-bold uppercase mb-0.5 block">Item</label>
                            <select 
                                value={cartItem.itemId}
                                onChange={(e) => handleItemChange(index, 'itemId', e.target.value)}
                                className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm py-2"
                            >
                                <option value="" disabled>Select Item</option>
                                {inventory.map(item => {
                                    if (activeCategory !== 'ALL' && item.category !== activeCategory && item.id !== cartItem.itemId) return null;
                                    return (
                                        <option key={item.id} value={item.id}>
                                            {item.name}
                                        </option>
                                    );
                                })}
                            </select>
                        </div>
                        <div className="w-24">
                            <label className="text-[10px] text-slate-400 font-bold uppercase mb-0.5 block">Price (Ksh)</label>
                            <input 
                                type="number" 
                                min="0"
                                value={cartItem.price}
                                onChange={(e) => handleItemChange(index, 'price', parseFloat(e.target.value) || 0)}
                                className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm py-2 px-2"
                            />
                        </div>
                        <div className="w-16">
                            <label className="text-[10px] text-slate-400 font-bold uppercase mb-0.5 block">Qty</label>
                            <input 
                                type="number" 
                                min="1"
                                value={cartItem.quantity}
                                onChange={(e) => handleItemChange(index, 'quantity', parseInt(e.target.value) || 1)}
                                className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm py-2 px-2 text-center"
                            />
                        </div>
                        <div className="pt-6">
                            <button 
                                type="button"
                                onClick={() => handleRemoveItem(index)}
                                disabled={cartItems.length === 1}
                                className={`p-2 rounded-lg transition-colors ${
                                    cartItems.length === 1 
                                    ? 'text-slate-300 cursor-not-allowed' 
                                    : 'text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20'
                                }`}
                            >
                                <Trash2 size={16} />
                            </button>
                        </div>
                    </div>
                 );
             })}

             <button 
                type="button"
                onClick={handleAddItem}
                className="w-full py-2 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-lg text-slate-500 dark:text-slate-400 text-xs font-bold uppercase tracking-wide hover:border-primary hover:text-primary transition-all flex items-center justify-center gap-2"
             >
                <Plus size={14} />
                Add Another Item
             </button>
          </div>

          <div className="flex justify-between items-center p-3 bg-slate-100 dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700">
            <span className="text-sm font-bold text-slate-500 uppercase">
                {type === 'DELIVERY' ? 'Total Cost' : 'Grand Total'}
            </span>
            <span className="text-xl font-black text-slate-900 dark:text-white">{formatKsh(grandTotal)}</span>
          </div>

          {/* Delivery Specifics */}
          {type === 'DELIVERY' && (
            <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                <div className="flex gap-4">
                    <div className="flex-1">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Clock size={12} /> Time Received
                        </label>
                        <input 
                        type="time" 
                        value={timeReceived}
                        onChange={(e) => setTimeReceived(e.target.value)}
                        className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                    <div className="flex-1">
                         <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <FileText size={12} /> PO Number
                        </label>
                        <input 
                        type="text" 
                        placeholder="PO-2023-001"
                        value={poNumber}
                        onChange={(e) => setPoNumber(e.target.value)}
                        className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <User size={12} /> Driver Name
                        </label>
                        <input 
                          type="text" 
                          placeholder="John Doe"
                          value={driverName}
                          onChange={(e) => setDriverName(e.target.value)}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Car size={12} /> Plate Number
                        </label>
                        <input 
                          type="text" 
                          placeholder="ABC 1234"
                          value={plateNumber}
                          onChange={(e) => setPlateNumber(e.target.value)}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                </div>
            </div>
          )}

          {/* Sale Specifics (Payment) */}
          {type === 'SALE' && (
            <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <User size={12} /> Customer Name (Optional)
                    </label>
                    <input 
                      type="text" 
                      placeholder="e.g. Walk-in or Company Name"
                      value={customerName}
                      onChange={(e) => setCustomerName(e.target.value)}
                      className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                    />
                 </div>

                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <CreditCard size={12} /> Payment Method <span className="text-red-500">*</span>
                    </label>
                    <div className="flex gap-2">
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('CASH')}
                            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg border text-sm font-bold transition-all ${
                                paymentMethod === 'CASH' 
                                ? 'bg-emerald-500 text-white border-emerald-600 shadow-sm' 
                                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700'
                            }`}
                        >
                            <Banknote size={16} />
                            Cash
                        </button>
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('MPESA')}
                            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg border text-sm font-bold transition-all ${
                                paymentMethod === 'MPESA' 
                                ? 'bg-emerald-500 text-white border-emerald-600 shadow-sm' 
                                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700'
                            }`}
                        >
                            <Smartphone size={16} />
                            M-Pesa
                        </button>
                    </div>
                 </div>

                 {paymentMethod === 'MPESA' && (
                     <div className="animate-in fade-in slide-in-from-top-1 duration-200">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Receipt size={12} /> Transaction Code <span className="text-red-500">*</span>
                        </label>
                        <input 
                          type="text" 
                          required={paymentMethod === 'MPESA'}
                          placeholder="e.g. QEH83729"
                          value={mpesaCode}
                          onChange={(e) => setMpesaCode(e.target.value.toUpperCase())}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm uppercase font-mono"
                        />
                     </div>
                 )}
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">
                {type === 'DELIVERY' ? 'Additional Notes' : 'Notes / Remarks'}
            </label>
            <textarea 
              rows={2}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder={type === 'SALE' ? "Additional sale info..." : type === 'RETURN' ? "e.g., Damaged item" : "Optional notes..."}
              className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
            ></textarea>
          </div>

          {/* Log/Receipt Preview Section */}
          {(type === 'DELIVERY' || type === 'SALE') && previewText && (
            <div className="mt-2 p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 rounded-lg animate-in fade-in slide-in-from-top-2 duration-300">
               <div className="flex items-center gap-2 mb-1.5">
                 {type === 'SALE' ? <Receipt size={12} className="text-blue-500"/> : <Eye size={12} className="text-blue-500" />}
                 <p className="text-[10px] font-bold text-blue-500 uppercase tracking-wide">
                    {type === 'SALE' ? 'Sale Summary' : 'Log Preview'}
                 </p>
               </div>
               <div className="text-sm text-slate-700 dark:text-slate-300 font-mono whitespace-pre-wrap pl-5 border-l-2 border-blue-200 dark:border-blue-800">
                 {previewText}
               </div>
            </div>
          )}

          <div className="flex justify-end gap-3 pt-4 border-t border-slate-100 dark:border-slate-800 mt-2 shrink-0">
            <button 
              type="button" 
              onClick={onClose}
              className="px-4 py-2 text-sm font-medium text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors"
            >
              Cancel
            </button>
            <button 
              type="submit"
              className="flex items-center gap-2 px-4 py-2 bg-primary text-white rounded-lg text-sm font-bold hover:bg-primary-dark transition-colors shadow-lg shadow-primary/20"
            >
              <Save size={16} />
              Confirm {type === 'SALE' ? 'Sale' : 'Action'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default ActionModal;

import React from 'react';

export interface InventoryItem {
  id: string;
  name: string;
  sku: string;
  category: 'TOOLS' | 'MATERIALS' | 'PPE';
  stockLevel: number;
  maxStock: number;
  unit: string;
  status: 'In Stock' | 'Low Stock' | 'Out of Stock';
  buyingPrice: number; // Cost to purchase
  sellingPrice: number; // Price to sell
}

export interface ActivityItem {
  id: string;
  title: string;
  description: string;
  timestamp: string;
  type: 'LOG' | 'SALE' | 'ALERT' | 'RETURN';
}

export interface Metric {
  title: string;
  value: string;
  trend?: string;
  trendType?: 'positive' | 'negative' | 'neutral';
  icon: React.ElementType;
  colorClass: string;
  footerText?: string;
  footerClass?: string;
}

export interface SidebarLink {
  label: string;
  icon: React.ElementType;
  active?: boolean;
  badge?: string;
}

export interface ReceiptItem {
  itemName: string;
  quantity: number;
  unitPrice: number;
  total: number;
}

export interface ReceiptData {
  transactionId: string;
  date: string;
  customerName: string;
  items: ReceiptItem[];
  totalPrice: number;
  paymentMethod: 'CASH' | 'MPESA';
  mpesaCode?: string;
}

export interface DailyStats {
  revenue: number;
  profit: number;
  transactionCount: number;
}

import React, { useState } from 'react';
import { Truck, BarChart3, ShoppingCart } from 'lucide-react'; 
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import StatCards from './components/StatCards';
import InventoryTable from './components/InventoryTable';
import QuickActions from './components/QuickActions';
import RecentActivity from './components/RecentActivity';
import ActionModal from './components/ActionModal';
import ReceiptModal from './components/ReceiptModal';
import { INVENTORY_DATA, RECENT_ACTIVITY } from './constants';
import { InventoryItem, ActivityItem, ReceiptData, ReceiptItem, DailyStats } from './types';

function App() {
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [inventory, setInventory] = useState<InventoryItem[]>(INVENTORY_DATA);
  const [activities, setActivities] = useState<ActivityItem[]>(RECENT_ACTIVITY);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLowStockFilterActive, setIsLowStockFilterActive] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Track Daily Stats (Revenue & Profit)
  // Initialized with dummy data to match the UI mockup feel
  const [dailyStats, setDailyStats] = useState<DailyStats>({
    revenue: 45200,
    profit: 12500,
    transactionCount: 14
  });

  // Modal State
  const [modalState, setModalState] = useState<{
    isOpen: boolean;
    type: 'DELIVERY' | 'SALE' | 'RETURN' | null;
  }>({ isOpen: false, type: null });

  // Receipt State
  const [receiptState, setReceiptState] = useState<{
    isOpen: boolean;
    data: ReceiptData | null;
  }>({ isOpen: false, data: null });

  // Filter Logic Helper
  const getFilteredData = (categoryFilter?: string) => {
    return inventory.filter(item => {
      const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            item.sku.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesFilter = isLowStockFilterActive ? (item.status === 'Low Stock' || item.status === 'Out of Stock') : true;
      const matchesCategory = categoryFilter ? item.category === categoryFilter : true;

      return matchesSearch && matchesFilter && matchesCategory;
    });
  };

  // Updated to accept price
  const handleAction = (items: { itemId: string; quantity: number; price: number }[], notes: string, meta?: any) => {
    // Generate Timestamp ID for the entire batch
    const transactionId = Date.now().toString();
    const shortId = transactionId.slice(-6);

    let updatedInventory = [...inventory];
    let totalItemsProcessed = 0;
    const receiptItems: ReceiptItem[] = [];

    // Track batch financial impact
    let batchRevenue = 0;
    let batchProfit = 0;

    // Process each item in the batch
    items.forEach(cartItem => {
      const itemIndex = updatedInventory.findIndex(i => i.id === cartItem.itemId);
      if (itemIndex === -1) return;

      const item = updatedInventory[itemIndex];
      let newStockLevel = item.stockLevel;

      if (modalState.type === 'DELIVERY') {
        newStockLevel += cartItem.quantity;
      } else if (modalState.type === 'SALE') {
        newStockLevel = Math.max(0, newStockLevel - cartItem.quantity);

        // Calculate Revenue and Profit for this item
        // Profit = (Selling Price [Manual/Override] - Buying Price [Cost]) * Quantity
        const itemRevenue = cartItem.price * cartItem.quantity;
        const itemCost = item.buyingPrice * cartItem.quantity;

        batchRevenue += itemRevenue;
        batchProfit += (itemRevenue - itemCost);

      } else if (modalState.type === 'RETURN') {
        newStockLevel += cartItem.quantity;
        // Logic for returns could arguably reduce revenue/profit, 
        // but for simplicity we'll just handle stock for now or assume separate refund flow.
      }

      // Update Status based on new stock
      let newStatus: InventoryItem['status'] = 'In Stock';
      if (newStockLevel === 0) newStatus = 'Out of Stock';
      else if (newStockLevel < item.maxStock * 0.2) newStatus = 'Low Stock';

      // Update the inventory array
      updatedInventory[itemIndex] = {
        ...item,
        stockLevel: newStockLevel,
        status: newStatus
      };

      totalItemsProcessed += cartItem.quantity;

      // Prepare data for receipt if it's a sale
      if (modalState.type === 'SALE') {
        receiptItems.push({
          itemName: item.name,
          quantity: cartItem.quantity,
          unitPrice: cartItem.price, // Use the overridden price
          total: cartItem.price * cartItem.quantity
        });
      }
    });

    setInventory(updatedInventory);

    // Update Daily Stats if Sale
    if (modalState.type === 'SALE') {
        setDailyStats(prev => ({
            revenue: prev.revenue + batchRevenue,
            profit: prev.profit + batchProfit,
            transactionCount: prev.transactionCount + 1
        }));
    }

    // Create a summarized Activity Log entry
    let activityTitle = '';
    let activityType: ActivityItem['type'] = 'LOG';

    const firstItemName = updatedInventory.find(i => i.id === items[0].itemId)?.name || 'Unknown Item';
    const otherCount = items.length - 1;
    const itemSummary = otherCount > 0 ? `${firstItemName} +${otherCount} others` : firstItemName;

    if (modalState.type === 'DELIVERY') {
      activityTitle = `Delivery: ${totalItemsProcessed} Items`;
      activityType = 'LOG';
    } else if (modalState.type === 'SALE') {
      activityTitle = `Sale: ${itemSummary}`;
      activityType = 'SALE';
    } else if (modalState.type === 'RETURN') {
      activityTitle = `Return: ${itemSummary}`;
      activityType = 'RETURN';
    }

    // Add Activity
    const newActivity: ActivityItem = {
      id: transactionId,
      title: activityTitle,
      description: notes || `Manual entry (${items.length} line items)`,
      timestamp: 'Just now',
      type: activityType
    };
    setActivities([newActivity, ...activities]);

    // If Sale, trigger receipt with all items
    if (modalState.type === 'SALE' && meta) {
        setReceiptState({
            isOpen: true,
            data: {
                transactionId: shortId,
                date: new Date().toLocaleString(),
                customerName: meta.customerName || 'Walk-in Customer',
                items: receiptItems,
                totalPrice: meta.totalPrice,
                paymentMethod: meta.paymentMethod,
                mpesaCode: meta.mpesaCode
            }
        });
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'Inventory':
        return (
          <div className="space-y-6 animate-in fade-in duration-500">
             <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <h2 className="text-xl sm:text-2xl font-bold dark:text-white">Full Store Inventory</h2>
             </div>
             <InventoryTable 
                data={getFilteredData()} 
                filterActive={isLowStockFilterActive}
                onFilterToggle={() => setIsLowStockFilterActive(!isLowStockFilterActive)}
             />
          </div>
        );
      case 'Sales':
        const salesLogs = activities.filter(a => a.type === 'SALE');
        return (
          <div className="space-y-6 animate-in fade-in duration-500">
             <div className="flex items-center justify-between">
                <h2 className="text-xl sm:text-2xl font-bold dark:text-white">Sales History</h2>
             </div>
             <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
                  {salesLogs.length > 0 ? (
                    <div className="divide-y divide-slate-200 dark:divide-slate-800">
                      {salesLogs.map(log => (
                        <div key={log.id} className="p-4 flex items-center gap-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                           <div className="size-10 rounded-full bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400 flex items-center justify-center shrink-0">
                              <ShoppingCart size={20} />
                           </div>
                           <div className="min-w-0 flex-1">
                              <p className="font-bold text-slate-900 dark:text-white truncate">{log.title}</p>
                              <p className="text-sm text-slate-500 truncate">{log.description}</p>
                           </div>
                           <div className="ml-auto text-xs font-bold text-slate-400 uppercase tracking-wide whitespace-nowrap">
                              {log.timestamp}
                           </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="p-8 text-center text-slate-500">No sales recorded yet.</div>
                  )}
               </div>
          </div>
        );
      case 'Deliveries':
         const deliveryLogs = activities.filter(a => a.type === 'LOG');
         return (
            <div className="space-y-6 animate-in fade-in duration-500">
               <h2 className="text-xl sm:text-2xl font-bold dark:text-white">Incoming Deliveries</h2>
               <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
                  {deliveryLogs.length > 0 ? (
                    <div className="divide-y divide-slate-200 dark:divide-slate-800">
                      {deliveryLogs.map(log => (
                        <div key={log.id} className="p-4 flex items-center gap-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                           <div className="size-10 rounded-full bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400 flex items-center justify-center shrink-0">
                              <Truck size={20} />
                           </div>
                           <div className="min-w-0 flex-1">
                              <p className="font-bold text-slate-900 dark:text-white truncate">{log.title}</p>
                              <p className="text-sm text-slate-500 truncate">{log.description}</p>
                           </div>
                           <div className="ml-auto text-xs font-bold text-slate-400 uppercase tracking-wide whitespace-nowrap">
                              {log.timestamp}
                           </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="p-8 text-center text-slate-500">No delivery logs found.</div>
                  )}
               </div>
            </div>
         );
      case 'Reports':
        return (
           <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400 animate-in fade-in duration-500">
              <div className="size-24 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center mb-6">
                 <BarChart3 size={40} className="text-slate-300 dark:text-slate-600" />
              </div>
              <h2 className="text-xl font-bold text-slate-600 dark:text-slate-300">Analytics & Reports</h2>
              <p className="text-sm mt-2">This module is currently under development.</p>
           </div>
        );
      case 'Dashboard':
      default:
        return (
          <div className="animate-in fade-in duration-500">
            <StatCards inventory={inventory} stats={dailyStats} />
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8 pb-8">
              <div className="col-span-1 lg:col-span-8">
                <InventoryTable 
                  data={getFilteredData()} 
                  filterActive={isLowStockFilterActive}
                  onFilterToggle={() => setIsLowStockFilterActive(!isLowStockFilterActive)}
                />
              </div>
              <div className="col-span-1 lg:col-span-4 space-y-6 lg:space-y-8">
                <QuickActions 
                  onAction={(type) => setModalState({ isOpen: true, type })} 
                />
                <RecentActivity activities={activities} />
              </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        onTabChange={(tab) => {
          setActiveTab(tab);
          setIsMobileMenuOpen(false);
        }} 
        isOpen={isMobileMenuOpen}
        onClose={() => setIsMobileMenuOpen(false)}
      />

      <main className="flex-1 flex flex-col overflow-hidden bg-background-light dark:bg-background-dark relative">
        <Header 
          onSearch={setSearchQuery} 
          searchValue={searchQuery}
          onMenuClick={() => setIsMobileMenuOpen(true)}
        />

        <div className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8 scroll-smooth">
          <div className="max-w-[1600px] mx-auto">
             {renderContent()}
          </div>
        </div>
      </main>

      {/* Action Modal */}
      <ActionModal 
        isOpen={modalState.isOpen}
        type={modalState.type}
        onClose={() => setModalState({ ...modalState, isOpen: false })}
        onSubmit={handleAction}
        inventory={inventory}
      />

      {/* Receipt Modal */}
      <ReceiptModal 
        isOpen={receiptState.isOpen}
        data={receiptState.data}
        onClose={() => setReceiptState({ isOpen: false, data: null })}
      />
    </div>
  );
}

