             <h3 className="text-lg font-bold text-slate-600 dark:text-slate-300">No Purchase Orders</h3>
             <p className="text-slate-400 text-sm mt-1">Create a new LPO to restock your inventory.</p>
          </div>
        )}
      </div>
    </div>
  );
};

