      case 'Returns':
         const returnLogs = activities.filter(a => a.type === 'RETURN');
         return (
            <div className="space-y-6 animate-in fade-in duration-500">
               <h2 className="text-xl sm:text-2xl font-bold dark:text-white flex items-center gap-2">
