      default:
        return (
          <div className="animate-in fade-in duration-500">
            <StatCards inventory={inventory} stats={dailyStats} />
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8 pb-8">
              <div className="col-span-1 lg:col-span-8">
                <InventoryTable 
                  data={getFilteredData()} 
                  filterActive={isLowStockFilterActive}
                  onFilterToggle={() => setIsLowStockFilterActive(!isLowStockFilterActive)}
                />
              </div>
              <div className="col-span-1 lg:col-span-4 space-y-6 lg:space-y-8">
                <QuickActions 
                  onAction={(type) => setModalState({ isOpen: true, type })} 
                />
                <RecentActivity activities={activities} />
              </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        onTabChange={(tab) => {
          setActiveTab(tab);
          setIsMobileMenuOpen(false);
        }} 
        isOpen={isMobileMenuOpen}
        onClose={() => setIsMobileMenuOpen(false)}
      />

      <main className="flex-1 flex flex-col overflow-hidden bg-background-light dark:bg-background-dark relative">
        <Header 
          onSearch={setSearchQuery} 
          searchValue={searchQuery}
          onMenuClick={() => setIsMobileMenuOpen(true)}
        />

        <div className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8 scroll-smooth">
          <div className="max-w-[1600px] mx-auto">
             {renderContent()}
          </div>
        </div>
      </main>

      {/* Action Modal */}
      <ActionModal 
        isOpen={modalState.isOpen}
        type={modalState.type}
        onClose={() => setModalState({ ...modalState, isOpen: false })}
        onSubmit={handleAction}
        inventory={inventory}
      />

      {/* Receipt Modal */}
      <ReceiptModal 
        isOpen={receiptState.isOpen}
        data={receiptState.data}
        onClose={() => setReceiptState({ isOpen: false, data: null })}
      />

      {/* LPO Modal */}
      <LPOModal
        isOpen={lpoModalState.isOpen}
        lpo={lpoModalState.lpo}
        onClose={() => setLpoModalState({ isOpen: false, lpo: null })}
      />

      {/* Return Preview Modal */}
      <ReturnPreviewModal
        isOpen={returnPreviewState.isOpen}
        data={returnPreviewState.data}
        onClose={() => setReturnPreviewState({ isOpen: false, data: null })}
      />
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { Truck, BarChart3, ShoppingCart, RotateCcw, Eye } from 'lucide-react'; 
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import StatCards from './components/StatCards';
import InventoryTable from './components/InventoryTable';
import QuickActions from './components/QuickActions';
import RecentActivity from './components/RecentActivity';
import ActionModal from './components/ActionModal';
import ReceiptModal from './components/ReceiptModal';
import LPOList from './components/LPOList';
import LPOModal from './components/LPOModal';
import ReturnPreviewModal from './components/ReturnPreviewModal';
import { INVENTORY_DATA, RECENT_ACTIVITY } from './constants';
import { InventoryItem, ActivityItem, ReceiptData, ReceiptItem, DailyStats, LPO } from './types';

function App() {
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [inventory, setInventory] = useState<InventoryItem[]>(INVENTORY_DATA);
  const [activities, setActivities] = useState<ActivityItem[]>(RECENT_ACTIVITY);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLowStockFilterActive, setIsLowStockFilterActive] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // LPO State
  const [lpos, setLpos] = useState<LPO[]>([]);

  // LPO Modal State
  const [lpoModalState, setLpoModalState] = useState<{
    isOpen: boolean;
    lpo: LPO | null;
  }>({ isOpen: false, lpo: null });

  // Return Preview Modal State
  const [returnPreviewState, setReturnPreviewState] = useState<{
    isOpen: boolean;
    data: any;
  }>({ isOpen: false, data: null });

  // Track Daily Stats (Revenue & Profit)
  // Initialized with dummy data to match the UI mockup feel
  const [dailyStats, setDailyStats] = useState<DailyStats>({
    revenue: 45200,
    profit: 12500,
    transactionCount: 14
  });

  // Modal State
  const [modalState, setModalState] = useState<{
    isOpen: boolean;
    type: 'DELIVERY' | 'SALE' | 'RETURN' | 'LPO' | null;
  }>({ isOpen: false, type: null });

  // Receipt State
  const [receiptState, setReceiptState] = useState<{
    isOpen: boolean;
    data: ReceiptData | null;
  }>({ isOpen: false, data: null });

  // Filter Logic Helper
  const getFilteredData = (categoryFilter?: string) => {
    return inventory.filter(item => {
      const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            item.sku.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesFilter = isLowStockFilterActive ? (item.status === 'Low Stock' || item.status === 'Out of Stock') : true;
      const matchesCategory = categoryFilter ? item.category === categoryFilter : true;

      return matchesSearch && matchesFilter && matchesCategory;
    });
  };

  // Handle LPO Status Changes (e.g., Receiving items updates stock)
  const handleLPOStatusChange = (lpoId: string, newStatus: LPO['status']) => {
    const lpo = lpos.find(l => l.id === lpoId);
    if (!lpo) return;

    if (newStatus === 'Received' && lpo.status !== 'Received') {
        // Update Inventory
        const updatedInventory = [...inventory];
        lpo.items.forEach(orderItem => {
            const itemIndex = updatedInventory.findIndex(i => i.id === orderItem.itemId);
            if (itemIndex > -1) {
                updatedInventory[itemIndex] = {
                    ...updatedInventory[itemIndex],
                    stockLevel: updatedInventory[itemIndex].stockLevel + orderItem.quantity,
                    status: (updatedInventory[itemIndex].stockLevel + orderItem.quantity) > 0 ? 'In Stock' : 'Out of Stock'
                };
            }
        });
        setInventory(updatedInventory);

        // Add Activity Log
        const newActivity: ActivityItem = {
            id: Date.now().toString(),
            title: `LPO Received: ${lpo.supplierName}`,
            description: `Order #${lpo.lpoNumber} • ${lpo.items.length} items added to stock`,
            timestamp: 'Just now',
            type: 'LOG'
        };
        setActivities([newActivity, ...activities]);
    }

    // Update LPO Status
    setLpos(prev => prev.map(p => p.id === lpoId ? { ...p, status: newStatus } : p));
  };

  // Updated to accept price
  const handleAction = (items: { itemId: string; quantity: number; price: number }[], notes: string, meta?: any) => {
    // Generate Timestamp ID for the entire batch
    const transactionId = Date.now().toString();
    const shortId = transactionId.slice(-6);

    // If it's an LPO, we don't update inventory immediately, we just create the LPO record
    if (modalState.type === 'LPO') {
        const newLPO: LPO = {
            id: transactionId,
            lpoNumber: `PO-${shortId}`,
            supplierName: meta.supplierName,
            dateIssued: new Date().toLocaleDateString(),
            expectedDate: meta.expectedDate,
            status: 'Pending',
            items: items.map(i => {
                const invItem = inventory.find(inv => inv.id === i.itemId);
                return {
                    itemId: i.itemId,
                    itemName: invItem?.name || 'Unknown',
                    quantity: i.quantity,
                    unitCost: i.price,
                    totalCost: i.price * i.quantity
                };
            }),
            totalExpectedCost: meta.totalExpectedCost,
            notes
        };
        setLpos([newLPO, ...lpos]);

        // Log creation
        setActivities([{
            id: transactionId,
            title: `New LPO Created`,
            description: `Order #${newLPO.lpoNumber} for ${meta.supplierName}`,
            timestamp: 'Just now',
            type: 'LPO'
        }, ...activities]);

        // Trigger LPO Modal immediately after creation if desired, or let user open it from list
        setLpoModalState({ isOpen: true, lpo: newLPO });

        return; // Stop here, don't update inventory yet
    }

    let updatedInventory = [...inventory];
    let totalItemsProcessed = 0;
    const receiptItems: ReceiptItem[] = [];

    // Track batch financial impact
    let batchRevenue = 0;
    let batchProfit = 0;

    // Process each item in the batch
    items.forEach(cartItem => {
      const itemIndex = updatedInventory.findIndex(i => i.id === cartItem.itemId);
      if (itemIndex === -1) return;

      const item = updatedInventory[itemIndex];
      let newStockLevel = item.stockLevel;

      if (modalState.type === 'DELIVERY') {
        newStockLevel += cartItem.quantity;
      } else if (modalState.type === 'SALE') {
        newStockLevel = Math.max(0, newStockLevel - cartItem.quantity);

        // Calculate Revenue and Profit for this item
        // Profit = (Selling Price [Manual/Override] - Buying Price [Cost]) * Quantity
        const itemRevenue = cartItem.price * cartItem.quantity;
        const itemCost = item.buyingPrice * cartItem.quantity;

        batchRevenue += itemRevenue;
        batchProfit += (itemRevenue - itemCost);

      } else if (modalState.type === 'RETURN') {
        newStockLevel += cartItem.quantity;
        // Logic for returns could arguably reduce revenue/profit, 
        // but for simplicity we'll just handle stock for now or assume separate refund flow.
      }

      // Update Status based on new stock
      let newStatus: InventoryItem['status'] = 'In Stock';
      if (newStockLevel === 0) newStatus = 'Out of Stock';
      else if (newStockLevel < item.maxStock * 0.2) newStatus = 'Low Stock';

      // Update the inventory array
      updatedInventory[itemIndex] = {
        ...item,
        stockLevel: newStockLevel,
        status: newStatus
      };

      totalItemsProcessed += cartItem.quantity;

      // Prepare data for receipt if it's a sale
      if (modalState.type === 'SALE') {
        receiptItems.push({
          itemName: item.name,
          quantity: cartItem.quantity,
          unitPrice: cartItem.price, // Use the overridden price
          total: cartItem.price * cartItem.quantity
        });
      }
    });

    setInventory(updatedInventory);

    // Update Daily Stats if Sale
    if (modalState.type === 'SALE') {
        setDailyStats(prev => ({
            revenue: prev.revenue + batchRevenue,
            profit: prev.profit + batchProfit,
            transactionCount: prev.transactionCount + 1
        }));
    }

    // Create a summarized Activity Log entry
    let activityTitle = '';
    let activityType: ActivityItem['type'] = 'LOG';
    let activityDescription = notes || `Manual entry (${items.length} line items)`;
    let activityMeta: any = null;

    const firstItemName = updatedInventory.find(i => i.id === items[0].itemId)?.name || 'Unknown Item';
    const otherCount = items.length - 1;
    const itemSummary = otherCount > 0 ? `${firstItemName} +${otherCount} others` : firstItemName;

    if (modalState.type === 'DELIVERY') {
      activityTitle = `Delivery: ${totalItemsProcessed} Items`;
      activityType = 'LOG';
    } else if (modalState.type === 'SALE') {
      activityTitle = `Sale: ${itemSummary}`;
      activityType = 'SALE';

      activityMeta = {
          transactionId: shortId,
          date: new Date().toLocaleString(),
          customerName: meta?.customerName || 'Walk-in Customer',
          items: receiptItems,
          totalPrice: meta?.totalPrice || 0,
          paymentMethod: meta?.paymentMethod || 'CASH',
          mpesaCode: meta?.mpesaCode
      };
    } else if (modalState.type === 'RETURN') {
      activityTitle = `Return: ${itemSummary}`;
      activityType = 'RETURN';

      const itemDetails = items.map(i => {
         const invItem = updatedInventory.find(inv => inv.id === i.itemId);
         return `${i.quantity}x ${invItem?.name || 'Unknown'}`;
      }).join(', ');

      activityDescription = notes ? `${itemDetails} • ${notes}` : itemDetails;

      activityMeta = {
        returnId: `RET-${shortId}`,
        originalDate: new Date().toLocaleDateString(),
        notes: notes,
        items: items.map(i => ({
             itemId: i.itemId,
             itemName: updatedInventory.find(inv => inv.id === i.itemId)?.name || 'Unknown',
             quantity: i.quantity,
             price: i.price
        }))
      };
    }

    // Add Activity
    const newActivity: ActivityItem = {
      id: transactionId,
      title: activityTitle,
      description: activityDescription,
      timestamp: 'Just now',
      type: activityType,
      meta: activityMeta
    };
    setActivities([newActivity, ...activities]);

    // If Sale, trigger receipt with all items
    if (modalState.type === 'SALE' && meta) {
        setReceiptState({
            isOpen: true,
            data: {
                transactionId: shortId,
                date: new Date().toLocaleString(),
                customerName: meta.customerName || 'Walk-in Customer',
                items: receiptItems,
                totalPrice: meta.totalPrice,
                paymentMethod: meta.paymentMethod,
                mpesaCode: meta.mpesaCode
            }
        });
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'Inventory':
        return (
          <div className="space-y-6 animate-in fade-in duration-500">
             <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <h2 className="text-xl sm:text-2xl font-bold dark:text-white">Full Store Inventory</h2>
             </div>
             <InventoryTable 
                data={getFilteredData()} 
                filterActive={isLowStockFilterActive}
                onFilterToggle={() => setIsLowStockFilterActive(!isLowStockFilterActive)}
             />
          </div>
        );
      case 'Sales':
        const salesLogs = activities.filter(a => a.type === 'SALE');
        return (
          <div className="space-y-6 animate-in fade-in duration-500">
             <div className="flex items-center justify-between">
                <h2 className="text-xl sm:text-2xl font-bold dark:text-white">Sales History</h2>
             </div>
             <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
                  {salesLogs.length > 0 ? (
                    <div className="divide-y divide-slate-200 dark:divide-slate-800">
                      {salesLogs.map(log => (
                        <div key={log.id} className="p-4 flex items-center gap-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                           <div className="size-10 rounded-full bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400 flex items-center justify-center shrink-0">
                              <ShoppingCart size={20} />
                           </div>
                           <div className="min-w-0 flex-1">
                              <p className="font-bold text-slate-900 dark:text-white truncate">{log.title}</p>
                              <p className="text-sm text-slate-500 truncate">{log.description}</p>
                           </div>
                           <div className="ml-auto flex items-center gap-4">
                               <div className="text-xs font-bold text-slate-400 uppercase tracking-wide whitespace-nowrap hidden sm:block">
                                  {log.timestamp}
                               </div>
                               {log.meta && (
                                   <button 
                                     onClick={() => setReceiptState({ isOpen: true, data: log.meta })}
                                     className="p-2 text-slate-400 hover:text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg transition-colors"
                                     title="View Receipt"
                                   >
                                      <Eye size={18} />
                                   </button>
                               )}
                           </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="p-8 text-center text-slate-500">No sales recorded yet.</div>
                  )}
               </div>
          </div>
        );
      case 'LPO':
        return (
            <div className="space-y-6 animate-in fade-in duration-500">
                <LPOList 
                    lpos={lpos} 
                    onStatusChange={handleLPOStatusChange}
                    onPrint={(lpo) => setLpoModalState({ isOpen: true, lpo })} 
                />
            </div>
        );
      case 'Deliveries':
         const deliveryLogs = activities.filter(a => a.type === 'LOG');
         return (
            <div className="space-y-6 animate-in fade-in duration-500">
               <h2 className="text-xl sm:text-2xl font-bold dark:text-white">Incoming Deliveries</h2>
               <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
                  {deliveryLogs.length > 0 ? (
                    <div className="divide-y divide-slate-200 dark:divide-slate-800">
                      {deliveryLogs.map(log => (
                        <div key={log.id} className="p-4 flex items-center gap-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                           <div className="size-10 rounded-full bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400 flex items-center justify-center shrink-0">
                              <Truck size={20} />
                           </div>
                           <div className="min-w-0 flex-1">
                              <p className="font-bold text-slate-900 dark:text-white truncate">{log.title}</p>
                              <p className="text-sm text-slate-500 truncate">{log.description}</p>
                           </div>
                           <div className="ml-auto text-xs font-bold text-slate-400 uppercase tracking-wide whitespace-nowrap">
                              {log.timestamp}
                           </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="p-8 text-center text-slate-500">No delivery logs found.</div>
                  )}
               </div>
            </div>
         );
      case 'Returns':
         const returnLogs = activities.filter(a => a.type === 'RETURN');
         return (
            <div className="space-y-6 animate-in fade-in duration-500">
               <h2 className="text-xl sm:text-2xl font-bold dark:text-white flex items-center gap-2">
                  <RotateCcw size={24} className="text-slate-400" />
                  Customer Returns
               </h2>
               <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
                  {returnLogs.length > 0 ? (
                    <div className="divide-y divide-slate-200 dark:divide-slate-800">
                      {returnLogs.map(log => (
                        <div key={log.id} className="p-4 flex items-center gap-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                           <div className="size-10 rounded-full bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400 flex items-center justify-center shrink-0">
                              <RotateCcw size={20} />
                           </div>
                           <div className="min-w-0 flex-1">
                              <p className="font-bold text-slate-900 dark:text-white truncate">
                                {log.title.startsWith('Return:') ? log.title.replace('Return:', '').trim() : log.title}
                              </p>
                              <p className="text-sm text-slate-500">
                                {log.description}
                              </p>
                           </div>

                           <div className="flex items-center gap-4">
                               <div className="text-xs font-bold text-slate-400 uppercase tracking-wide whitespace-nowrap hidden sm:block">
                                  {log.timestamp}
                               </div>
                               {/* Only show preview button if we have metadata, or if it's a legacy item just disable/hide logic */}
                               <button 
                                 onClick={() => {
                                   // If legacy log without meta, fallback or show generic info
                                   const metaData = log.meta || { items: [], notes: log.description }; 
                                   setReturnPreviewState({ isOpen: true, data: metaData })
                                 }}
                                 className="p-2 text-slate-400 hover:text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg transition-colors"
                                 title="Preview Return Details"
                               >
                                  <Eye size={18} />
                               </button>
                           </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="p-8 text-center text-slate-500">No returns recorded yet.</div>
                  )}
               </div>
            </div>
         );
      case 'Reports':
        return (
           <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400 animate-in fade-in duration-500">
              <div className="size-24 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center mb-6">
                 <BarChart3 size={40} className="text-slate-300 dark:text-slate-600" />
              </div>
              <h2 className="text-xl font-bold text-slate-600 dark:text-slate-300">Analytics & Reports</h2>
              <p className="text-sm mt-2">This module is currently under development.</p>
           </div>
        );
      case 'Dashboard':
      default:
        return (
          <div className="animate-in fade-in duration-500">
            <StatCards inventory={inventory} stats={dailyStats} />
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8 pb-8">
              <div className="col-span-1 lg:col-span-8">
                <InventoryTable 
                  data={getFilteredData()} 
                  filterActive={isLowStockFilterActive}
                  onFilterToggle={() => setIsLowStockFilterActive(!isLowStockFilterActive)}
                />
              </div>
              <div className="col-span-1 lg:col-span-4 space-y-6 lg:space-y-8">
                <QuickActions 
                  onAction={(type) => setModalState({ isOpen: true, type })} 
                />
                <RecentActivity activities={activities} />
              </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        onTabChange={(tab) => {
          setActiveTab(tab);
          setIsMobileMenuOpen(false);
        }} 
        isOpen={isMobileMenuOpen}
        onClose={() => setIsMobileMenuOpen(false)}
      />

      <main className="flex-1 flex flex-col overflow-hidden bg-background-light dark:bg-background-dark relative">
        <Header 
          onSearch={setSearchQuery} 
          searchValue={searchQuery}
          onMenuClick={() => setIsMobileMenuOpen(true)}
        />

        <div className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8 scroll-smooth">
          <div className="max-w-[1600px] mx-auto">
             {renderContent()}
          </div>
        </div>
      </main>

      {/* Action Modal */}
      <ActionModal 
        isOpen={modalState.isOpen}
        type={modalState.type}
        onClose={() => setModalState({ ...modalState, isOpen: false })}
        onSubmit={handleAction}
        inventory={inventory}
      />

      {/* Receipt Modal */}
      <ReceiptModal 
        isOpen={receiptState.isOpen}
        data={receiptState.data}
        onClose={() => setReceiptState({ isOpen: false, data: null })}
      />

      {/* LPO Modal */}
      <LPOModal
        isOpen={lpoModalState.isOpen}
        lpo={lpoModalState.lpo}
        onClose={() => setLpoModalState({ isOpen: false, lpo: null })}
      />

      {/* Return Preview Modal */}
      <ReturnPreviewModal
        isOpen={returnPreviewState.isOpen}
        data={returnPreviewState.data}
        onClose={() => setReturnPreviewState({ isOpen: false, data: null })}
      />
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { X, Save, FileText, User, Car, Clock, Eye, Layers, Package, Wrench, HardHat, CreditCard, Banknote, Smartphone, Plus, Trash2, Building2, Calendar, PackagePlus, ArrowLeft } from 'lucide-react';
import { InventoryItem } from '../types';

interface ActionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (items: { itemId: string; quantity: number; price: number }[], notes: string, meta?: any) => void;
  type: 'DELIVERY' | 'SALE' | 'RETURN' | 'LPO' | null;
  inventory: InventoryItem[];
}

interface CartItem {
  itemId: string;
  quantity: number;
  price: number;
  isNew?: boolean;
  newItemData?: {
      name: string;
      category: 'TOOLS' | 'MATERIALS' | 'PPE';
      unit: string;
      sellingPrice: number;
  };
}

const ActionModal: React.FC<ActionModalProps> = ({ isOpen, onClose, onSubmit, type, inventory }) => {
  // State for multiple items
  const [cartItems, setCartItems] = useState<CartItem[]>([{ itemId: '', quantity: 1, price: 0 }]);

  const [notes, setNotes] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  // Delivery specific fields
  const [poNumber, setPoNumber] = useState('');
  const [driverName, setDriverName] = useState('');
  const [plateNumber, setPlateNumber] = useState('');
  const [timeReceived, setTimeReceived] = useState('');

  // Sale specific fields
  const [customerName, setCustomerName] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'MPESA'>('CASH');
  const [mpesaCode, setMpesaCode] = useState('');

  // LPO Specific fields
  const [supplierName, setSupplierName] = useState('');
  const [expectedDate, setExpectedDate] = useState('');

  // Filter inventory for the dropdowns
  const filteredInventory = inventory.filter(item => 
    activeCategory === 'ALL' ? true : item.category === activeCategory
  );

  // Helper to format currency
  const formatKsh = (amount: number) => {
    return `Ksh ${amount.toLocaleString()}`;
  };

  // Helper to get active price based on transaction type
  const getTransactionPrice = (item: InventoryItem) => {
    // If we are Buying (Delivery) or Ordering (LPO), use Buying Price (Cost)
    if (type === 'DELIVERY' || type === 'LPO') return item.buyingPrice;
    return item.sellingPrice; // SALE or RETURN
  };

  // Calculate Totals
  const calculateTotal = () => {
    return cartItems.reduce((sum, cartItem) => {
      return sum + (cartItem.price * cartItem.quantity);
    }, 0);
  };

  const grandTotal = calculateTotal();

  // Reset form when modal opens
  useEffect(() => {
    if (isOpen) {
      setActiveCategory('ALL');

      // Initialize with first available item and its price
      const defaultItem = inventory[0];
      const defaultPrice = defaultItem ? getTransactionPrice(defaultItem) : 0;

      setCartItems([{ 
        itemId: defaultItem?.id || '', 
        quantity: 1, 
        price: defaultPrice,
        isNew: false 
      }]);

      setNotes('');
      setPoNumber('');
      setDriverName('');
      setPlateNumber('');
      setCustomerName('');
      setPaymentMethod('CASH');
      setMpesaCode('');
      setSupplierName('');
      setExpectedDate('');

      const now = new Date();
      setTimeReceived(`${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`);
    }
  }, [isOpen, inventory, type]);

  // --- Item Management Handlers ---

  const handleAddItem = () => {
    // Add new row with first available item in current filter
    const defaultItem = filteredInventory[0] || inventory[0];
    const defaultId = defaultItem?.id || '';
    const defaultPrice = defaultItem ? getTransactionPrice(defaultItem) : 0;

    setCartItems([...cartItems, { itemId: defaultId, quantity: 1, price: defaultPrice, isNew: false }]);
  };

  const handleRemoveItem = (index: number) => {
    if (cartItems.length > 1) {
      const newItems = [...cartItems];
      newItems.splice(index, 1);
      setCartItems(newItems);
    }
  };

  const handleItemChange = (index: number, field: keyof CartItem, value: any) => {
    const newItems = [...cartItems];

    if (field === 'itemId') {
      // When item changes, also update the price default
      const item = inventory.find(i => i.id === value);
      const newPrice = item ? getTransactionPrice(item) : 0;
      newItems[index] = { 
        ...newItems[index], 
        itemId: String(value), 
        price: newPrice 
      };
    } else {
      // @ts-ignore
      newItems[index] = { ...newItems[index], [field]: value };
    }

    setCartItems(newItems);
  };

  const handleNewItemDataChange = (index: number, field: string, value: any) => {
    const newItems = [...cartItems];
    if (newItems[index].newItemData) {
        newItems[index].newItemData = { ...newItems[index].newItemData!, [field]: value };
        setCartItems(newItems);
    }
  };

  const toggleNewItemMode = (index: number) => {
    const newItems = [...cartItems];
    const current = newItems[index];

    if (!current.isNew) {
        // Switch TO new item mode
        newItems[index] = {
            ...current,
            itemId: `NEW_${Date.now()}_${index}`, // Temp ID
            isNew: true,
            newItemData: { 
                name: '', 
                category: 'TOOLS', 
                unit: 'pcs', 
                sellingPrice: 0 
            },
            price: 0 // Reset cost to 0 for user to input
        };
    } else {
        // Switch BACK to existing item mode
        const defaultItem = filteredInventory[0] || inventory[0];
        newItems[index] = {
            ...current,
            itemId: defaultItem?.id || '',
            isNew: false,
            newItemData: undefined,
            price: defaultItem ? getTransactionPrice(defaultItem) : 0
        };
    }
    setCartItems(newItems);
  };

  // --- Preview Logic ---

  const getPreviewText = () => {
    const itemCount = cartItems.length;
    const itemSummary = cartItems.map(c => {
        if (c.isNew && c.newItemData) {
            return `${c.newItemData.name} (New) (x${c.quantity})`;
        }
        const i = inventory.find(inv => inv.id === c.itemId);
        return i ? `${i.name} (x${c.quantity})` : 'Unknown';
    }).join(', ');

    if (type === 'DELIVERY') {
        const details = [
            `Items (${itemCount}): ${itemSummary}`,
            poNumber && `PO: ${poNumber}`,
            driverName && `Driver: ${driverName}`,
            plateNumber && `Plate: ${plateNumber}`,
            timeReceived && `Time: ${timeReceived}`,
            `Total Cost: ${formatKsh(grandTotal)}`
        ].filter(Boolean).join(' • ');
        return notes ? `${details} \nNote: ${notes}` : details;
    } else if (type === 'SALE') {
        const paymentDetails = paymentMethod === 'CASH' ? 'Cash' : `M-Pesa: ${mpesaCode}`;
        const details = [
            `Items: ${itemSummary}`,
            customerName && `Customer: ${customerName}`,
            `Payment: ${paymentDetails}`,
            `Total: ${formatKsh(grandTotal)}`
        ].filter(Boolean).join(' • ');
        return notes ? `${details} \nNote: ${notes}` : details;
    } else if (type === 'LPO') {
       const details = [
            `Supplier: ${supplierName || 'N/A'}`,
            `Items: ${itemSummary}`,
            `Est. Cost: ${formatKsh(grandTotal)}`,
            expectedDate && `Expected: ${expectedDate}`
       ].filter(Boolean).join(' • ');
       return notes ? `${details} \nNote: ${notes}` : details;
    }
    return notes;
  };

  const previewText = getPreviewText();

  if (!isOpen || !type) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Validate fields
    if (type === 'SALE' && paymentMethod === 'MPESA' && !mpesaCode.trim()) {
        return; 
    }

    if (type === 'LPO' && !supplierName.trim()) {
        alert("Please enter a Supplier Name");
        return;
    }

    // Validate new items
    for (const item of cartItems) {
        if (item.isNew) {
            if (!item.newItemData?.name.trim()) {
                alert("Please enter a name for the new item.");
                return;
            }
        } else if (!item.itemId) {
            // Filter out empty existing items if any
            continue;
        }
    }

    const validItems = cartItems.filter(i => i.itemId);
    if (validItems.length === 0) return;

    let submissionNotes = notes;
    let metaData: any = {};
    const newItemsDefinitions = cartItems
        .filter(i => i.isNew && i.newItemData)
        .map(i => ({
            tempId: i.itemId,
            ...i.newItemData,
            buyingPrice: i.price // Current price input is the buying cost
        }));

    if (type === 'DELIVERY') {
      submissionNotes = getPreviewText();
    } else if (type === 'SALE') {
      const paymentDetails = paymentMethod === 'CASH' ? 'Cash' : `M-Pesa: ${mpesaCode}`;
      submissionNotes = `${customerName ? `Cust: ${customerName}` : 'Walk-in'} • ${paymentDetails} • Total: ${formatKsh(grandTotal)}`;
      if (notes) submissionNotes += ` • ${notes}`;

      metaData = {
        customerName,
        paymentMethod,
        mpesaCode,
        totalPrice: grandTotal
      };
    } else if (type === 'LPO') {
      submissionNotes = getPreviewText();
      metaData = {
        supplierName,
        expectedDate,
        totalExpectedCost: grandTotal,
        newItemsDefinitions: newItemsDefinitions
      };
    }

    onSubmit(validItems, submissionNotes, metaData);
    onClose();
  };

  const getTitle = () => {
    switch(type) {
      case 'DELIVERY': return 'Log Incoming Delivery';
      case 'SALE': return 'Record New Sale';
      case 'RETURN': return 'Log Customer Return';
      case 'LPO': return 'Create Purchase Order (LPO)';
      default: return '';
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 rounded-xl w-full max-w-lg shadow-2xl border border-slate-200 dark:border-slate-800 scale-100 animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto flex flex-col m-4">
        <div className="flex items-center justify-between p-6 border-b border-slate-100 dark:border-slate-800 sticky top-0 bg-white dark:bg-slate-900 z-10 shrink-0">
          <h3 className="text-lg font-bold text-slate-900 dark:text-white">{getTitle()}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-500 dark:hover:text-slate-300">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4 flex-1 overflow-y-auto">

          {/* Category Filter - Only show if not in new item mode largely */}
          {!cartItems.every(i => i.isNew) && (
            <div className="sticky top-0 bg-white dark:bg-slate-900 z-10 pb-2">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">Filter Item List</label>
                <div className="flex p-1 bg-slate-100 dark:bg-slate-800 rounded-lg gap-1">
                    {[
                    { id: 'ALL', icon: Layers, label: 'All' },
                    { id: 'TOOLS', icon: Wrench, label: 'Tools' },
                    { id: 'MATERIALS', icon: Package, label: 'Materials' },
                    { id: 'PPE', icon: HardHat, label: 'PPE' }
                    ].map((cat) => (
                    <button
                        key={cat.id}
                        type="button"
                        onClick={() => setActiveCategory(cat.id)}
                        className={`flex-1 flex items-center justify-center gap-1.5 py-2 text-[10px] font-bold uppercase rounded-md transition-all ${
                        activeCategory === cat.id
                            ? 'bg-white dark:bg-slate-700 text-primary shadow-sm ring-1 ring-slate-200 dark:ring-slate-600'
                            : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 hover:bg-slate-200/50 dark:hover:bg-slate-700/50'
                        }`}
                    >
                        <cat.icon size={12} />
                        <span className="hidden sm:inline">{cat.label}</span>
                    </button>
                    ))}
                </div>
            </div>
          )}

          {/* Item List */}
          <div className="space-y-3">
             <div className="flex justify-between items-end">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide">
                    Items ({cartItems.length})
                </label>
             </div>

             {cartItems.map((cartItem, index) => {
                 return (
                    <div key={index} className={`flex flex-col gap-2 p-3 rounded-lg border transition-all ${cartItem.isNew ? 'bg-blue-50/50 border-blue-200 dark:bg-blue-900/10 dark:border-blue-800' : 'border-transparent'}`}>
                        <div className="flex gap-2 items-start">
                             {/* Item Select / Name Input */}
                            <div className="flex-1 min-w-0">
                                <label className="text-[10px] text-slate-400 font-bold uppercase mb-0.5 block flex justify-between">
                                    {cartItem.isNew ? 'New Item Name' : 'Item'}
                                    {cartItem.isNew && <span className="text-blue-500">Manual Entry</span>}
                                </label>
                                {cartItem.isNew ? (
                                    <input 
                                        type="text" 
                                        placeholder="Enter Item Name"
                                        value={cartItem.newItemData?.name || ''}
                                        onChange={(e) => handleNewItemDataChange(index, 'name', e.target.value)}
                                        className="w-full rounded-lg border-blue-200 dark:border-blue-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-blue-500 focus:border-blue-500 text-sm py-2"
                                        autoFocus
                                    />
                                ) : (
                                    <div className="flex gap-1">
                                        <select 
                                            value={cartItem.itemId}
                                            onChange={(e) => handleItemChange(index, 'itemId', e.target.value)}
                                            className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm py-2"
                                        >
                                            <option value="" disabled>Select Item</option>
                                            {inventory.map(item => {
                                                if (activeCategory !== 'ALL' && item.category !== activeCategory && item.id !== cartItem.itemId) return null;
                                                return (
                                                    <option key={item.id} value={item.id}>
                                                        {item.name}
                                                    </option>
                                                );
                                            })}
                                        </select>
                                    </div>
                                )}
                            </div>

                            {/* Type Toggle for LPO */}
                            {type === 'LPO' && (
                                <div className="pt-6">
                                    <button 
                                        type="button"
                                        onClick={() => toggleNewItemMode(index)}
                                        className={`p-2 rounded-lg transition-colors border ${
                                            cartItem.isNew 
                                            ? 'bg-blue-100 text-blue-600 border-blue-200 dark:bg-blue-900/30 dark:text-blue-400 dark:border-blue-700' 
                                            : 'bg-slate-100 text-slate-400 border-slate-200 dark:bg-slate-800 dark:border-slate-700 hover:text-primary hover:border-primary'
                                        }`}
                                        title={cartItem.isNew ? "Select Existing Item" : "Create New Item"}
                                    >
                                        {cartItem.isNew ? <ArrowLeft size={16} /> : <PackagePlus size={16} />}
                                    </button>
                                </div>
                            )}

                            {/* Remove Button */}
                            <div className="pt-6">
                                <button 
                                    type="button"
                                    onClick={() => handleRemoveItem(index)}
                                    disabled={cartItems.length === 1}
                                    className={`p-2 rounded-lg transition-colors ${
                                        cartItems.length === 1 
                                        ? 'text-slate-300 cursor-not-allowed' 
                                        : 'text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20'
                                    }`}
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </div>

                        {/* Second Row: Price & Quantity */}
                        <div className="flex gap-2">
                             <div className="flex-1">
                                <label className="text-[10px] text-slate-400 font-bold uppercase mb-0.5 block">
                                    {type === 'LPO' ? 'Unit Cost (Ksh)' : 'Price (Ksh)'}
                                </label>
                                <input 
                                    type="number" 
                                    min="0"
                                    value={cartItem.price}
                                    onChange={(e) => handleItemChange(index, 'price', parseFloat(e.target.value) || 0)}
                                    className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm py-2 px-2"
                                />
                            </div>
                            <div className="w-24">
                                <label className="text-[10px] text-slate-400 font-bold uppercase mb-0.5 block">Qty</label>
                                <input 
                                    type="number" 
                                    min="1"
                                    value={cartItem.quantity}
                                    onChange={(e) => handleItemChange(index, 'quantity', parseInt(e.target.value) || 1)}
                                    className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm py-2 px-2 text-center"
                                />
                            </div>
                        </div>

                        {/* Third Row: Extra fields for New Items */}
                        {cartItem.isNew && (
                            <div className="grid grid-cols-3 gap-2 pt-1 animate-in slide-in-from-top-2 duration-200">
                                <div>
                                    <label className="text-[10px] text-blue-400 font-bold uppercase mb-0.5 block">Category</label>
                                    <select 
                                        value={cartItem.newItemData?.category}
                                        onChange={(e) => handleNewItemDataChange(index, 'category', e.target.value)}
                                        className="w-full rounded-lg border-blue-200 dark:border-blue-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-blue-500 focus:border-blue-500 text-xs py-1.5"
                                    >
                                        <option value="TOOLS">Tools</option>
                                        <option value="MATERIALS">Materials</option>
                                        <option value="PPE">PPE</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="text-[10px] text-blue-400 font-bold uppercase mb-0.5 block">Unit</label>
                                    <input 
                                        type="text"
                                        placeholder="pcs, kg..." 
                                        value={cartItem.newItemData?.unit}
                                        onChange={(e) => handleNewItemDataChange(index, 'unit', e.target.value)}
                                        className="w-full rounded-lg border-blue-200 dark:border-blue-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-blue-500 focus:border-blue-500 text-xs py-1.5 px-2"
                                    />
                                </div>
                                <div>
                                    <label className="text-[10px] text-blue-400 font-bold uppercase mb-0.5 block">Selling Price</label>
                                    <input 
                                        type="number"
                                        min="0"
                                        value={cartItem.newItemData?.sellingPrice}
                                        onChange={(e) => handleNewItemDataChange(index, 'sellingPrice', parseFloat(e.target.value) || 0)}
                                        className="w-full rounded-lg border-blue-200 dark:border-blue-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-blue-500 focus:border-blue-500 text-xs py-1.5 px-2"
                                    />
                                </div>
                            </div>
                        )}
                    </div>
                 );
             })}

             <button 
                type="button"
                onClick={handleAddItem}
                className="w-full py-2 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-lg text-slate-500 dark:text-slate-400 text-xs font-bold uppercase tracking-wide hover:border-primary hover:text-primary transition-all flex items-center justify-center gap-2"
             >
                <Plus size={14} />
                Add Another Item
             </button>
          </div>

          <div className="flex justify-between items-center p-3 bg-slate-100 dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700">
            <span className="text-sm font-bold text-slate-500 uppercase">
                {type === 'DELIVERY' || type === 'LPO' ? 'Total Cost' : 'Grand Total'}
            </span>
            <span className="text-xl font-black text-slate-900 dark:text-white">{formatKsh(grandTotal)}</span>
          </div>

          {/* LPO Specifics */}
          {type === 'LPO' && (
             <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <Building2 size={12} /> Supplier Name <span className="text-red-500">*</span>
                    </label>
                    <input 
                      type="text" 
                      placeholder="e.g. Apex Cement Distributors Ltd"
                      value={supplierName}
                      onChange={(e) => setSupplierName(e.target.value)}
                      className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                    />
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <Calendar size={12} /> Expected Delivery Date (Optional)
                    </label>
                    <input 
                      type="date" 
                      value={expectedDate}
                      onChange={(e) => setExpectedDate(e.target.value)}
                      className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                    />
                 </div>
             </div>
          )}

          {/* Delivery Specifics */}
          {type === 'DELIVERY' && (
            <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                <div className="flex gap-4">
                    <div className="flex-1">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Clock size={12} /> Time Received
                        </label>
                        <input 
                        type="time" 
                        value={timeReceived}
                        onChange={(e) => setTimeReceived(e.target.value)}
                        className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                    <div className="flex-1">
                         <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <FileText size={12} /> PO Number
                        </label>
                        <input 
                        type="text" 
                        placeholder="PO-2023-001"
                        value={poNumber}
                        onChange={(e) => setPoNumber(e.target.value)}
                        className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <User size={12} /> Driver Name
                        </label>
                        <input 
                          type="text" 
                          placeholder="John Doe"
                          value={driverName}
                          onChange={(e) => setDriverName(e.target.value)}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Car size={12} /> Plate Number
                        </label>
                        <input 
                          type="text" 
                          placeholder="ABC 1234"
                          value={plateNumber}
                          onChange={(e) => setPlateNumber(e.target.value)}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                </div>
            </div>
          )}

          {/* Sale Specifics (Payment) */}
          {type === 'SALE' && (
            <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <User size={12} /> Customer Name (Optional)
                    </label>
                    <input 
                      type="text" 
                      placeholder="e.g. Walk-in or Company Name"
                      value={customerName}
                      onChange={(e) => setCustomerName(e.target.value)}
                      className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                    />
                 </div>

                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <CreditCard size={12} /> Payment Method <span className="text-red-500">*</span>
                    </label>
                    <div className="flex gap-2">
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('CASH')}
                            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg border text-sm font-bold transition-all ${
                                paymentMethod === 'CASH' 
                                ? 'bg-emerald-500 text-white border-emerald-600 shadow-sm' 
                                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700'
                            }`}
                        >
                            <Banknote size={16} />
                            Cash
                        </button>
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('MPESA')}
                            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg border text-sm font-bold transition-all ${
                                paymentMethod === 'MPESA' 
                                ? 'bg-emerald-500 text-white border-emerald-600 shadow-sm' 
                                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700'
                            }`}
                        >
                            <Smartphone size={16} />
                            M-Pesa
                        </button>
                    </div>
                 </div>

                 {paymentMethod === 'MPESA' && (
                     <div className="animate-in fade-in slide-in-from-top-1 duration-200">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Receipt size={12} /> Transaction Code <span className="text-red-500">*</span>
                        </label>
                        <input 
                          type="text" 
                          required={paymentMethod === 'MPESA'}
                          placeholder="e.g. QEH83729"
                          value={mpesaCode}
                          onChange={(e) => setMpesaCode(e.target.value.toUpperCase())}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm uppercase font-mono"
                        />
                     </div>
                 )}
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">
                {type === 'DELIVERY' ? 'Additional Notes' : type === 'LPO' ? 'Order Notes' : 'Notes / Remarks'}
            </label>
            <textarea 
              rows={2}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder={type === 'SALE' ? "Additional sale info..." : type === 'RETURN' ? "e.g., Damaged item" : "Optional notes..."}
              className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
            ></textarea>
          </div>

          {/* Log/Receipt Preview Section */}
          {(type === 'DELIVERY' || type === 'SALE' || type === 'LPO') && previewText && (
            <div className="mt-2 p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 rounded-lg animate-in fade-in slide-in-from-top-2 duration-300">
               <div className="flex items-center gap-2 mb-1.5">
                 {type === 'SALE' ? <CreditCard size={12} className="text-blue-500"/> : <Eye size={12} className="text-blue-500" />}
                 <p className="text-[10px] font-bold text-blue-500 uppercase tracking-wide">
                    {type === 'SALE' ? 'Sale Summary' : type === 'LPO' ? 'Order Preview' : 'Log Preview'}
                 </p>
               </div>
               <div className="text-sm text-slate-700 dark:text-slate-300 font-mono whitespace-pre-wrap pl-5 border-l-2 border-blue-200 dark:border-blue-800">
                 {previewText}
               </div>
            </div>
          )}

          <div className="flex justify-end gap-3 pt-4 border-t border-slate-100 dark:border-slate-800 mt-2 shrink-0">
            <button 
              type="button" 
              onClick={onClose}
              className="px-4 py-2 text-sm font-medium text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors"
            >
              Cancel
            </button>
            <button 
              type="submit"
              className="flex items-center gap-2 px-4 py-2 bg-primary text-white rounded-lg text-sm font-bold hover:bg-primary-dark transition-colors shadow-lg shadow-primary/20"
            >
              <Save size={16} />
              Confirm {type === 'SALE' ? 'Sale' : type === 'LPO' ? 'Order' : 'Action'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default ActionModal;

import React, { useState } from 'react';
import { Truck, BarChart3, ShoppingCart, RotateCcw, Eye } from 'lucide-react'; 
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import StatCards from './components/StatCards';
import InventoryTable from './components/InventoryTable';
import QuickActions from './components/QuickActions';
import RecentActivity from './components/RecentActivity';
import ActionModal from './components/ActionModal';
import ReceiptModal from './components/ReceiptModal';
import LPOList from './components/LPOList';
import LPOModal from './components/LPOModal';
import ReturnPreviewModal from './components/ReturnPreviewModal';
import { INVENTORY_DATA, RECENT_ACTIVITY } from './constants';
import { InventoryItem, ActivityItem, ReceiptData, ReceiptItem, DailyStats, LPO } from './types';

function App() {
  const [activeTab, setActiveTab] = useState('Dashboard');
  const [inventory, setInventory] = useState<InventoryItem[]>(INVENTORY_DATA);
  const [activities, setActivities] = useState<ActivityItem[]>(RECENT_ACTIVITY);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLowStockFilterActive, setIsLowStockFilterActive] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // LPO State
  const [lpos, setLpos] = useState<LPO[]>([]);

  // LPO Modal State
  const [lpoModalState, setLpoModalState] = useState<{
    isOpen: boolean;
    lpo: LPO | null;
  }>({ isOpen: false, lpo: null });

  // Return Preview Modal State
  const [returnPreviewState, setReturnPreviewState] = useState<{
    isOpen: boolean;
    data: any;
  }>({ isOpen: false, data: null });

  // Track Daily Stats (Revenue & Profit)
  // Initialized with dummy data to match the UI mockup feel
  const [dailyStats, setDailyStats] = useState<DailyStats>({
    revenue: 45200,
    profit: 12500,
    transactionCount: 14
  });

  // Modal State
  const [modalState, setModalState] = useState<{
    isOpen: boolean;
    type: 'DELIVERY' | 'SALE' | 'RETURN' | 'LPO' | null;
  }>({ isOpen: false, type: null });

  // Receipt State
  const [receiptState, setReceiptState] = useState<{
    isOpen: boolean;
    data: ReceiptData | null;
  }>({ isOpen: false, data: null });

  // Filter Logic Helper
  const getFilteredData = (categoryFilter?: string) => {
    return inventory.filter(item => {
      const matchesSearch = item.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                            item.sku.toLowerCase().includes(searchQuery.toLowerCase());
      const matchesFilter = isLowStockFilterActive ? (item.status === 'Low Stock' || item.status === 'Out of Stock') : true;
      const matchesCategory = categoryFilter ? item.category === categoryFilter : true;

      return matchesSearch && matchesFilter && matchesCategory;
    });
  };

  // Handle LPO Status Changes (e.g., Receiving items updates stock)
  const handleLPOStatusChange = (lpoId: string, newStatus: LPO['status']) => {
    const lpo = lpos.find(l => l.id === lpoId);
    if (!lpo) return;

    if (newStatus === 'Received' && lpo.status !== 'Received') {
        // Update Inventory
        const updatedInventory = [...inventory];
        lpo.items.forEach(orderItem => {
            const itemIndex = updatedInventory.findIndex(i => i.id === orderItem.itemId);
            if (itemIndex > -1) {
                updatedInventory[itemIndex] = {
                    ...updatedInventory[itemIndex],
                    stockLevel: updatedInventory[itemIndex].stockLevel + orderItem.quantity,
                    status: (updatedInventory[itemIndex].stockLevel + orderItem.quantity) > 0 ? 'In Stock' : 'Out of Stock'
                };
            }
        });
        setInventory(updatedInventory);

        // Add Activity Log
        const newActivity: ActivityItem = {
            id: Date.now().toString(),
            title: `LPO Received: ${lpo.supplierName}`,
            description: `Order #${lpo.lpoNumber} • ${lpo.items.length} items added to stock`,
            timestamp: 'Just now',
            type: 'LOG'
        };
        setActivities([newActivity, ...activities]);
    }

    // Update LPO Status
    setLpos(prev => prev.map(p => p.id === lpoId ? { ...p, status: newStatus } : p));
  };

  // Updated to accept price
  const handleAction = (items: { itemId: string; quantity: number; price: number }[], notes: string, meta?: any) => {
    // Generate Timestamp ID for the entire batch
    const transactionId = Date.now().toString();
    const shortId = transactionId.slice(-6);

    // Check for NEW Manual Items first (mainly from LPO)
    // If we have manual items, we need to add them to inventory immediately as "Out of Stock" (placeholder)
    // so they are part of the system and valid for the LPO record.
    let currentInventory = [...inventory];
    let finalItems = [...items];

    if (meta?.newItemsDefinitions && meta.newItemsDefinitions.length > 0) {
        // Process new definitions
        meta.newItemsDefinitions.forEach((def: any) => {
            const newId = Date.now().toString() + Math.random().toString().slice(2,5);
            const newItem: InventoryItem = {
                id: newId,
                name: def.name,
                sku: `GEN-${newId.slice(-5)}`, // Auto-generated SKU
                category: def.category,
                stockLevel: 0, // Starts at 0 until received
                maxStock: 50, // Default max stock
                unit: def.unit,
                status: 'Out of Stock',
                buyingPrice: def.buyingPrice,
                sellingPrice: def.sellingPrice
            };

            // Add to local inventory array
            currentInventory.unshift(newItem);

            // Replace the temp ID in the items list with the real ID
            finalItems = finalItems.map(i => {
                if (i.itemId === def.tempId) {
                    return { ...i, itemId: newId };
                }
                return i;
            });
        });

        // Update global inventory state
        setInventory(currentInventory);
    }

    // If it's an LPO, we don't update inventory immediately, we just create the LPO record
    if (modalState.type === 'LPO') {
        const newLPO: LPO = {
            id: transactionId,
            lpoNumber: `PO-${shortId}`,
            supplierName: meta.supplierName,
            dateIssued: new Date().toLocaleDateString(),
            expectedDate: meta.expectedDate,
            status: 'Pending',
            items: finalItems.map(i => {
                const invItem = currentInventory.find(inv => inv.id === i.itemId);
                return {
                    itemId: i.itemId,
                    itemName: invItem?.name || 'Unknown',
                    quantity: i.quantity,
                    unitCost: i.price,
                    totalCost: i.price * i.quantity
                };
            }),
            totalExpectedCost: meta.totalExpectedCost,
            notes
        };
        setLpos([newLPO, ...lpos]);

        // Log creation
        setActivities([{
            id: transactionId,
            title: `New LPO Created`,
            description: `Order #${newLPO.lpoNumber} for ${meta.supplierName}`,
            timestamp: 'Just now',
            type: 'LPO'
        }, ...activities]);

        // Trigger LPO Modal immediately after creation if desired, or let user open it from list
        setLpoModalState({ isOpen: true, lpo: newLPO });

        return; // Stop here, don't update inventory (stock levels) yet
    }

    let updatedInventory = [...currentInventory]; // Use the potentially updated inventory
    let totalItemsProcessed = 0;
    const receiptItems: ReceiptItem[] = [];

    // Track batch financial impact
    let batchRevenue = 0;
    let batchProfit = 0;

    // Process each item in the batch
    finalItems.forEach(cartItem => {
      const itemIndex = updatedInventory.findIndex(i => i.id === cartItem.itemId);
      if (itemIndex === -1) return;

      const item = updatedInventory[itemIndex];
      let newStockLevel = item.stockLevel;

      if (modalState.type === 'DELIVERY') {
        newStockLevel += cartItem.quantity;
      } else if (modalState.type === 'SALE') {
        newStockLevel = Math.max(0, newStockLevel - cartItem.quantity);

        // Calculate Revenue and Profit for this item
        // Profit = (Selling Price [Manual/Override] - Buying Price [Cost]) * Quantity
        const itemRevenue = cartItem.price * cartItem.quantity;
        const itemCost = item.buyingPrice * cartItem.quantity;

        batchRevenue += itemRevenue;
        batchProfit += (itemRevenue - itemCost);

      } else if (modalState.type === 'RETURN') {
        newStockLevel += cartItem.quantity;
      }

      // Update Status based on new stock
      let newStatus: InventoryItem['status'] = 'In Stock';
      if (newStockLevel === 0) newStatus = 'Out of Stock';
      else if (newStockLevel < item.maxStock * 0.2) newStatus = 'Low Stock';

      // Update the inventory array
      updatedInventory[itemIndex] = {
        ...item,
        stockLevel: newStockLevel,
        status: newStatus
      };

      totalItemsProcessed += cartItem.quantity;

      // Prepare data for receipt if it's a sale
      if (modalState.type === 'SALE') {
        receiptItems.push({
          itemName: item.name,
          quantity: cartItem.quantity,
          unitPrice: cartItem.price, // Use the overridden price
          total: cartItem.price * cartItem.quantity
        });
      }
    });

    setInventory(updatedInventory);

    // Update Daily Stats if Sale
    if (modalState.type === 'SALE') {
        setDailyStats(prev => ({
            revenue: prev.revenue + batchRevenue,
            profit: prev.profit + batchProfit,
            transactionCount: prev.transactionCount + 1
        }));
    }

    // Create a summarized Activity Log entry
    let activityTitle = '';
    let activityType: ActivityItem['type'] = 'LOG';
    let activityDescription = notes || `Manual entry (${finalItems.length} line items)`;
    let activityMeta: any = null;

    const firstItemName = updatedInventory.find(i => i.id === finalItems[0].itemId)?.name || 'Unknown Item';
    const otherCount = finalItems.length - 1;
    const itemSummary = otherCount > 0 ? `${firstItemName} +${otherCount} others` : firstItemName;

    if (modalState.type === 'DELIVERY') {
      activityTitle = `Delivery: ${totalItemsProcessed} Items`;
      activityType = 'LOG';
    } else if (modalState.type === 'SALE') {
      activityTitle = `Sale: ${itemSummary}`;
      activityType = 'SALE';

      activityMeta = {
          transactionId: shortId,
          date: new Date().toLocaleString(),
          customerName: meta?.customerName || 'Walk-in Customer',
          items: receiptItems,
          totalPrice: meta?.totalPrice || 0,
          paymentMethod: meta?.paymentMethod || 'CASH',
          mpesaCode: meta?.mpesaCode
      };
    } else if (modalState.type === 'RETURN') {
      activityTitle = `Return: ${itemSummary}`;
      activityType = 'RETURN';

      const itemDetails = finalItems.map(i => {
         const invItem = updatedInventory.find(inv => inv.id === i.itemId);
         return `${i.quantity}x ${invItem?.name || 'Unknown'}`;
      }).join(', ');

      activityDescription = notes ? `${itemDetails} • ${notes}` : itemDetails;

      activityMeta = {
        returnId: `RET-${shortId}`,
        originalDate: new Date().toLocaleDateString(),
        notes: notes,
        items: finalItems.map(i => ({
             itemId: i.itemId,
             itemName: updatedInventory.find(inv => inv.id === i.itemId)?.name || 'Unknown',
             quantity: i.quantity,
             price: i.price
        }))
      };
    }

    // Add Activity
    const newActivity: ActivityItem = {
      id: transactionId,
      title: activityTitle,
      description: activityDescription,
      timestamp: 'Just now',
      type: activityType,
      meta: activityMeta
    };
    setActivities([newActivity, ...activities]);

    // If Sale, trigger receipt with all items
    if (modalState.type === 'SALE' && meta) {
        setReceiptState({
            isOpen: true,
            data: {
                transactionId: shortId,
                date: new Date().toLocaleString(),
                customerName: meta.customerName || 'Walk-in Customer',
                items: receiptItems,
                totalPrice: meta.totalPrice,
                paymentMethod: meta.paymentMethod,
                mpesaCode: meta.mpesaCode
            }
        });
    }
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'Inventory':
        return (
          <div className="space-y-6 animate-in fade-in duration-500">
             <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4">
                <h2 className="text-xl sm:text-2xl font-bold dark:text-white">Full Store Inventory</h2>
             </div>
             <InventoryTable 
                data={getFilteredData()} 
                filterActive={isLowStockFilterActive}
                onFilterToggle={() => setIsLowStockFilterActive(!isLowStockFilterActive)}
             />
          </div>
        );
      case 'Sales':
        const salesLogs = activities.filter(a => a.type === 'SALE');
        return (
          <div className="space-y-6 animate-in fade-in duration-500">
             <div className="flex items-center justify-between">
                <h2 className="text-xl sm:text-2xl font-bold dark:text-white">Sales History</h2>
             </div>
             <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
                  {salesLogs.length > 0 ? (
                    <div className="divide-y divide-slate-200 dark:divide-slate-800">
                      {salesLogs.map(log => (
                        <div key={log.id} className="p-4 flex items-center gap-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                           <div className="size-10 rounded-full bg-emerald-100 text-emerald-600 dark:bg-emerald-900/30 dark:text-emerald-400 flex items-center justify-center shrink-0">
                              <ShoppingCart size={20} />
                           </div>
                           <div className="min-w-0 flex-1">
                              <p className="font-bold text-slate-900 dark:text-white truncate">{log.title}</p>
                              <p className="text-sm text-slate-500 truncate">{log.description}</p>
                           </div>
                           <div className="ml-auto flex items-center gap-4">
                               <div className="text-xs font-bold text-slate-400 uppercase tracking-wide whitespace-nowrap hidden sm:block">
                                  {log.timestamp}
                               </div>
                               {log.meta && (
                                   <button 
                                     onClick={() => setReceiptState({ isOpen: true, data: log.meta })}
                                     className="p-2 text-slate-400 hover:text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg transition-colors"
                                     title="View Receipt"
                                   >
                                      <Eye size={18} />
                                   </button>
                               )}
                           </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="p-8 text-center text-slate-500">No sales recorded yet.</div>
                  )}
               </div>
          </div>
        );
      case 'LPO':
        return (
            <div className="space-y-6 animate-in fade-in duration-500">
                <LPOList 
                    lpos={lpos} 
                    onStatusChange={handleLPOStatusChange}
                    onPrint={(lpo) => setLpoModalState({ isOpen: true, lpo })} 
                />
            </div>
        );
      case 'Deliveries':
         const deliveryLogs = activities.filter(a => a.type === 'LOG');
         return (
            <div className="space-y-6 animate-in fade-in duration-500">
               <h2 className="text-xl sm:text-2xl font-bold dark:text-white">Incoming Deliveries</h2>
               <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
                  {deliveryLogs.length > 0 ? (
                    <div className="divide-y divide-slate-200 dark:divide-slate-800">
                      {deliveryLogs.map(log => (
                        <div key={log.id} className="p-4 flex items-center gap-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                           <div className="size-10 rounded-full bg-blue-100 text-blue-600 dark:bg-blue-900/30 dark:text-blue-400 flex items-center justify-center shrink-0">
                              <Truck size={20} />
                           </div>
                           <div className="min-w-0 flex-1">
                              <p className="font-bold text-slate-900 dark:text-white truncate">{log.title}</p>
                              <p className="text-sm text-slate-500 truncate">{log.description}</p>
                           </div>
                           <div className="ml-auto text-xs font-bold text-slate-400 uppercase tracking-wide whitespace-nowrap">
                              {log.timestamp}
                           </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="p-8 text-center text-slate-500">No delivery logs found.</div>
                  )}
               </div>
            </div>
         );
      case 'Returns':
         const returnLogs = activities.filter(a => a.type === 'RETURN');
         return (
            <div className="space-y-6 animate-in fade-in duration-500">
               <h2 className="text-xl sm:text-2xl font-bold dark:text-white flex items-center gap-2">
                  <RotateCcw size={24} className="text-slate-400" />
                  Customer Returns
               </h2>
               <div className="bg-white dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
                  {returnLogs.length > 0 ? (
                    <div className="divide-y divide-slate-200 dark:divide-slate-800">
                      {returnLogs.map(log => (
                        <div key={log.id} className="p-4 flex items-center gap-4 hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                           <div className="size-10 rounded-full bg-amber-100 text-amber-600 dark:bg-amber-900/30 dark:text-amber-400 flex items-center justify-center shrink-0">
                              <RotateCcw size={20} />
                           </div>
                           <div className="min-w-0 flex-1">
                              <p className="font-bold text-slate-900 dark:text-white truncate">
                                {log.title.startsWith('Return:') ? log.title.replace('Return:', '').trim() : log.title}
                              </p>
                              <p className="text-sm text-slate-500">
                                {log.description}
                              </p>
                           </div>

                           <div className="flex items-center gap-4">
                               <div className="text-xs font-bold text-slate-400 uppercase tracking-wide whitespace-nowrap hidden sm:block">
                                  {log.timestamp}
                               </div>
                               {/* Only show preview button if we have metadata, or if it's a legacy item just disable/hide logic */}
                               <button 
                                 onClick={() => {
                                   // If legacy log without meta, fallback or show generic info
                                   const metaData = log.meta || { items: [], notes: log.description }; 
                                   setReturnPreviewState({ isOpen: true, data: metaData })
                                 }}
                                 className="p-2 text-slate-400 hover:text-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg transition-colors"
                                 title="Preview Return Details"
                               >
                                  <Eye size={18} />
                               </button>
                           </div>
                        </div>
                      ))}
                    </div>
                  ) : (
                    <div className="p-8 text-center text-slate-500">No returns recorded yet.</div>
                  )}
               </div>
            </div>
         );
      case 'Reports':
        return (
           <div className="flex flex-col items-center justify-center h-[60vh] text-slate-400 animate-in fade-in duration-500">
              <div className="size-24 rounded-full bg-slate-100 dark:bg-slate-800 flex items-center justify-center mb-6">
                 <BarChart3 size={40} className="text-slate-300 dark:text-slate-600" />
              </div>
              <h2 className="text-xl font-bold text-slate-600 dark:text-slate-300">Analytics & Reports</h2>
              <p className="text-sm mt-2">This module is currently under development.</p>
           </div>
        );
      case 'Dashboard':
      default:
        return (
          <div className="animate-in fade-in duration-500">
            <StatCards inventory={inventory} stats={dailyStats} />
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8 pb-8">
              <div className="col-span-1 lg:col-span-8">
                <InventoryTable 
                  data={getFilteredData()} 
                  filterActive={isLowStockFilterActive}
                  onFilterToggle={() => setIsLowStockFilterActive(!isLowStockFilterActive)}
                />
              </div>
              <div className="col-span-1 lg:col-span-4 space-y-6 lg:space-y-8">
                <QuickActions 
                  onAction={(type) => setModalState({ isOpen: true, type })} 
                />
                <RecentActivity activities={activities} />
              </div>
            </div>
          </div>
        );
    }
  };

  return (
    <div className="flex h-screen overflow-hidden">
      <Sidebar 
        activeTab={activeTab} 
        onTabChange={(tab) => {
          setActiveTab(tab);
          setIsMobileMenuOpen(false);
        }} 
        isOpen={isMobileMenuOpen}
        onClose={() => setIsMobileMenuOpen(false)}
      />

      <main className="flex-1 flex flex-col overflow-hidden bg-background-light dark:bg-background-dark relative">
        <Header 
          onSearch={setSearchQuery} 
          searchValue={searchQuery}
          onMenuClick={() => setIsMobileMenuOpen(true)}
        />

        <div className="flex-1 overflow-y-auto p-4 md:p-6 lg:p-8 scroll-smooth">
          <div className="max-w-[1600px] mx-auto">
             {renderContent()}
          </div>
        </div>
      </main>

      {/* Action Modal */}
      <ActionModal 
        isOpen={modalState.isOpen}
        type={modalState.type}
        onClose={() => setModalState({ ...modalState, isOpen: false })}
        onSubmit={handleAction}
        inventory={inventory}
      />

      {/* Receipt Modal */}
      <ReceiptModal 
        isOpen={receiptState.isOpen}
        data={receiptState.data}
        onClose={() => setReceiptState({ isOpen: false, data: null })}
      />

      {/* LPO Modal */}
      <LPOModal
        isOpen={lpoModalState.isOpen}
        lpo={lpoModalState.lpo}
        onClose={() => setLpoModalState({ isOpen: false, lpo: null })}
      />

      {/* Return Preview Modal */}
      <ReturnPreviewModal
        isOpen={returnPreviewState.isOpen}
        data={returnPreviewState.data}
        onClose={() => setReturnPreviewState({ isOpen: false, data: null })}
      />
    </div>
  );
}

export default App;

import React, { useState, useEffect } from 'react';
import { X, Save, FileText, User, Car, Clock, Eye, Layers, Package, Wrench, HardHat, CreditCard, Banknote, Smartphone, Plus, Trash2, Building2, Calendar, PackagePlus, ArrowLeft, Receipt } from 'lucide-react';
import { InventoryItem } from '../types';

interface ActionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (items: { itemId: string; quantity: number; price: number }[], notes: string, meta?: any) => void;
  type: 'DELIVERY' | 'SALE' | 'RETURN' | 'LPO' | null;
  inventory: InventoryItem[];
}

interface CartItem {
  itemId: string;
  quantity: number;
  price: number;
  isNew?: boolean;
  newItemData?: {
      name: string;
      category: 'TOOLS' | 'MATERIALS' | 'PPE';
      unit: string;
      sellingPrice: number;
  };
}

const ActionModal: React.FC<ActionModalProps> = ({ isOpen, onClose, onSubmit, type, inventory }) => {
  // State for multiple items
  const [cartItems, setCartItems] = useState<CartItem[]>([{ itemId: '', quantity: 1, price: 0 }]);

  const [notes, setNotes] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  // Delivery specific fields
  const [poNumber, setPoNumber] = useState('');
  const [driverName, setDriverName] = useState('');
  const [plateNumber, setPlateNumber] = useState('');
  const [timeReceived, setTimeReceived] = useState('');

  // Sale specific fields
  const [customerName, setCustomerName] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'MPESA'>('CASH');
  const [mpesaCode, setMpesaCode] = useState('');

  // LPO Specific fields
  const [supplierName, setSupplierName] = useState('');
  const [expectedDate, setExpectedDate] = useState('');

  // Filter inventory for the dropdowns
  const filteredInventory = inventory.filter(item => 
    activeCategory === 'ALL' ? true : item.category === activeCategory
  );

  // Helper to format currency
  const formatKsh = (amount: number) => {
    return `Ksh ${amount.toLocaleString()}`;
  };

  // Helper to get active price based on transaction type
  const getTransactionPrice = (item: InventoryItem) => {
    // If we are Buying (Delivery) or Ordering (LPO), use Buying Price (Cost)
    if (type === 'DELIVERY' || type === 'LPO') return item.buyingPrice;
    return item.sellingPrice; // SALE or RETURN
  };

  // Calculate Totals
  const calculateTotal = () => {
    return cartItems.reduce((sum, cartItem) => {
      return sum + (cartItem.price * cartItem.quantity);
    }, 0);
  };

  const grandTotal = calculateTotal();

  // Reset form when modal opens
  useEffect(() => {
    if (isOpen) {
      setActiveCategory('ALL');

      // Initialize with first available item and its price
      const defaultItem = inventory[0];
      const defaultPrice = defaultItem ? getTransactionPrice(defaultItem) : 0;

      setCartItems([{ 
        itemId: defaultItem?.id || '', 
        quantity: 1, 
        price: defaultPrice,
        isNew: false 
      }]);

      setNotes('');
      setPoNumber('');
      setDriverName('');
      setPlateNumber('');
      setCustomerName('');
      setPaymentMethod('CASH');
      setMpesaCode('');
      setSupplierName('');
      setExpectedDate('');

      const now = new Date();
      setTimeReceived(`${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`);
    }
  }, [isOpen, inventory, type]);

  // --- Item Management Handlers ---

  const handleAddItem = () => {
    // Add new row with first available item in current filter
    const defaultItem = filteredInventory[0] || inventory[0];
    const defaultId = defaultItem?.id || '';
    const defaultPrice = defaultItem ? getTransactionPrice(defaultItem) : 0;

    setCartItems([...cartItems, { itemId: defaultId, quantity: 1, price: defaultPrice, isNew: false }]);
  };

  const handleRemoveItem = (index: number) => {
    if (cartItems.length > 1) {
      const newItems = [...cartItems];
      newItems.splice(index, 1);
      setCartItems(newItems);
    }
  };

  const handleItemChange = (index: number, field: keyof CartItem, value: any) => {
    const newItems = [...cartItems];

    if (field === 'itemId') {
      // When item changes, also update the price default
      const item = inventory.find(i => i.id === value);
      const newPrice = item ? getTransactionPrice(item) : 0;
      newItems[index] = { 
        ...newItems[index], 
        itemId: String(value), 
        price: newPrice 
      };
    } else {
      // @ts-ignore
      newItems[index] = { ...newItems[index], [field]: value };
    }

    setCartItems(newItems);
  };

  const handleNewItemDataChange = (index: number, field: string, value: any) => {
    const newItems = [...cartItems];
    if (newItems[index].newItemData) {
        newItems[index].newItemData = { ...newItems[index].newItemData!, [field]: value };
        setCartItems(newItems);
    }
  };

  const toggleNewItemMode = (index: number) => {
    const newItems = [...cartItems];
    const current = newItems[index];

    if (!current.isNew) {
        // Switch TO new item mode
        newItems[index] = {
            ...current,
            itemId: `NEW_${Date.now()}_${index}`, // Temp ID
            isNew: true,
            newItemData: { 
                name: '', 
                category: 'TOOLS', 
                unit: 'pcs', 
                sellingPrice: 0 
            },
            price: 0 // Reset cost to 0 for user to input
        };
    } else {
        // Switch BACK to existing item mode
        const defaultItem = filteredInventory[0] || inventory[0];
        newItems[index] = {
            ...current,
            itemId: defaultItem?.id || '',
            isNew: false,
            newItemData: undefined,
            price: defaultItem ? getTransactionPrice(defaultItem) : 0
        };
    }
    setCartItems(newItems);
  };

  // --- Preview Logic ---

  const getPreviewText = () => {
    const itemCount = cartItems.length;
    const itemSummary = cartItems.map(c => {
        if (c.isNew && c.newItemData) {
            return `${c.newItemData.name} (New) (x${c.quantity})`;
        }
        const i = inventory.find(inv => inv.id === c.itemId);
        return i ? `${i.name} (x${c.quantity})` : 'Unknown';
    }).join(', ');

    if (type === 'DELIVERY') {
        const details = [
            `Items (${itemCount}): ${itemSummary}`,
            poNumber && `PO: ${poNumber}`,
            driverName && `Driver: ${driverName}`,
            plateNumber && `Plate: ${plateNumber}`,
            timeReceived && `Time: ${timeReceived}`,
            `Total Cost: ${formatKsh(grandTotal)}`
        ].filter(Boolean).join(' • ');
        return notes ? `${details} \nNote: ${notes}` : details;
    } else if (type === 'SALE') {
        const paymentDetails = paymentMethod === 'CASH' ? 'Cash' : `M-Pesa: ${mpesaCode}`;
        const details = [
            `Items: ${itemSummary}`,
            customerName && `Customer: ${customerName}`,
            `Payment: ${paymentDetails}`,
            `Total: ${formatKsh(grandTotal)}`
        ].filter(Boolean).join(' • ');
        return notes ? `${details} \nNote: ${notes}` : details;
    } else if (type === 'LPO') {
       const details = [
            `Supplier: ${supplierName || 'N/A'}`,
            `Items: ${itemSummary}`,
            `Est. Cost: ${formatKsh(grandTotal)}`,
            expectedDate && `Expected: ${expectedDate}`
       ].filter(Boolean).join(' • ');
       return notes ? `${details} \nNote: ${notes}` : details;
    }
    return notes;
  };

  const previewText = getPreviewText();

  if (!isOpen || !type) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Validate fields
    if (type === 'SALE' && paymentMethod === 'MPESA' && !mpesaCode.trim()) {
        return; 
    }

    if (type === 'LPO' && !supplierName.trim()) {
        alert("Please enter a Supplier Name");
        return;
    }

    // Validate new items
    for (const item of cartItems) {
        if (item.isNew) {
            if (!item.newItemData?.name.trim()) {
                alert("Please enter a name for the new item.");
                return;
            }
        } else if (!item.itemId) {
            // Filter out empty existing items if any
            continue;
        }
    }

    const validItems = cartItems.filter(i => i.itemId);
    if (validItems.length === 0) return;

    let submissionNotes = notes;
    let metaData: any = {};
    const newItemsDefinitions = cartItems
        .filter(i => i.isNew && i.newItemData)
        .map(i => ({
            tempId: i.itemId,
            ...i.newItemData,
            buyingPrice: i.price // Current price input is the buying cost
        }));

    if (type === 'DELIVERY') {
      submissionNotes = getPreviewText();
    } else if (type === 'SALE') {
      const paymentDetails = paymentMethod === 'CASH' ? 'Cash' : `M-Pesa: ${mpesaCode}`;
      submissionNotes = `${customerName ? `Cust: ${customerName}` : 'Walk-in'} • ${paymentDetails} • Total: ${formatKsh(grandTotal)}`;
      if (notes) submissionNotes += ` • ${notes}`;

      metaData = {
        customerName,
        paymentMethod,
        mpesaCode,
        totalPrice: grandTotal
      };
    } else if (type === 'LPO') {
      submissionNotes = getPreviewText();
      metaData = {
        supplierName,
        expectedDate,
        totalExpectedCost: grandTotal,
        newItemsDefinitions: newItemsDefinitions
      };
    }

    onSubmit(validItems, submissionNotes, metaData);
    onClose();
  };

  const getTitle = () => {
    switch(type) {
      case 'DELIVERY': return 'Log Incoming Delivery';
      case 'SALE': return 'Record New Sale';
      case 'RETURN': return 'Log Customer Return';
      case 'LPO': return 'Create Purchase Order (LPO)';
      default: return '';
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/50 backdrop-blur-sm animate-in fade-in duration-200">
      <div className="bg-white dark:bg-slate-900 rounded-xl w-full max-w-lg shadow-2xl border border-slate-200 dark:border-slate-800 scale-100 animate-in zoom-in-95 duration-200 max-h-[90vh] overflow-y-auto flex flex-col m-4">
        <div className="flex items-center justify-between p-6 border-b border-slate-100 dark:border-slate-800 sticky top-0 bg-white dark:bg-slate-900 z-10 shrink-0">
          <h3 className="text-lg font-bold text-slate-900 dark:text-white">{getTitle()}</h3>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-500 dark:hover:text-slate-300">
            <X size={20} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6 space-y-4 flex-1 overflow-y-auto">

          {/* Category Filter - Only show if not in new item mode largely */}
          {!cartItems.every(i => i.isNew) && (
            <div className="sticky top-0 bg-white dark:bg-slate-900 z-10 pb-2">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">Filter Item List</label>
                <div className="flex p-1 bg-slate-100 dark:bg-slate-800 rounded-lg gap-1">
                    {[
                    { id: 'ALL', icon: Layers, label: 'All' },
                    { id: 'TOOLS', icon: Wrench, label: 'Tools' },
                    { id: 'MATERIALS', icon: Package, label: 'Materials' },
                    { id: 'PPE', icon: HardHat, label: 'PPE' }
                    ].map((cat) => (
                    <button
                        key={cat.id}
                        type="button"
                        onClick={() => setActiveCategory(cat.id)}
                        className={`flex-1 flex items-center justify-center gap-1.5 py-2 text-[10px] font-bold uppercase rounded-md transition-all ${
                        activeCategory === cat.id
                            ? 'bg-white dark:bg-slate-700 text-primary shadow-sm ring-1 ring-slate-200 dark:ring-slate-600'
                            : 'text-slate-500 hover:text-slate-700 dark:hover:text-slate-300 hover:bg-slate-200/50 dark:hover:bg-slate-700/50'
                        }`}
                    >
                        <cat.icon size={12} />
                        <span className="hidden sm:inline">{cat.label}</span>
                    </button>
                    ))}
                </div>
            </div>
          )}

          {/* Item List */}
          <div className="space-y-3">
             <div className="flex justify-between items-end">
                <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide">
                    Items ({cartItems.length})
                </label>
             </div>

             {cartItems.map((cartItem, index) => {
                 return (
                    <div key={index} className={`flex flex-col gap-2 p-3 rounded-lg border transition-all ${cartItem.isNew ? 'bg-blue-50/50 border-blue-200 dark:bg-blue-900/10 dark:border-blue-800' : 'border-transparent'}`}>
                        <div className="flex gap-2 items-start">
                             {/* Item Select / Name Input */}
                            <div className="flex-1 min-w-0">
                                <label className="text-[10px] text-slate-400 font-bold uppercase mb-0.5 block flex justify-between">
                                    {cartItem.isNew ? 'New Item Name' : 'Item'}
                                    {cartItem.isNew && <span className="text-blue-500">Manual Entry</span>}
                                </label>
                                {cartItem.isNew ? (
                                    <input 
                                        type="text" 
                                        placeholder="Enter Item Name"
                                        value={cartItem.newItemData?.name || ''}
                                        onChange={(e) => handleNewItemDataChange(index, 'name', e.target.value)}
                                        className="w-full rounded-lg border-blue-200 dark:border-blue-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-blue-500 focus:border-blue-500 text-sm py-2"
                                        autoFocus
                                    />
                                ) : (
                                    <div className="flex gap-1">
                                        <select 
                                            value={cartItem.itemId}
                                            onChange={(e) => handleItemChange(index, 'itemId', e.target.value)}
                                            className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm py-2"
                                        >
                                            <option value="" disabled>Select Item</option>
                                            {inventory.map(item => {
                                                if (activeCategory !== 'ALL' && item.category !== activeCategory && item.id !== cartItem.itemId) return null;
                                                return (
                                                    <option key={item.id} value={item.id}>
                                                        {item.name}
                                                    </option>
                                                );
                                            })}
                                        </select>
                                    </div>
                                )}
                            </div>

                            {/* Type Toggle for LPO */}
                            {type === 'LPO' && (
                                <div className="pt-6">
                                    <button 
                                        type="button"
                                        onClick={() => toggleNewItemMode(index)}
                                        className={`p-2 rounded-lg transition-colors border ${
                                            cartItem.isNew 
                                            ? 'bg-blue-100 text-blue-600 border-blue-200 dark:bg-blue-900/30 dark:text-blue-400 dark:border-blue-700' 
                                            : 'bg-slate-100 text-slate-400 border-slate-200 dark:bg-slate-800 dark:border-slate-700 hover:text-primary hover:border-primary'
                                        }`}
                                        title={cartItem.isNew ? "Select Existing Item" : "Create New Item"}
                                    >
                                        {cartItem.isNew ? <ArrowLeft size={16} /> : <PackagePlus size={16} />}
                                    </button>
                                </div>
                            )}

                            {/* Remove Button */}
                            <div className="pt-6">
                                <button 
                                    type="button"
                                    onClick={() => handleRemoveItem(index)}
                                    disabled={cartItems.length === 1}
                                    className={`p-2 rounded-lg transition-colors ${
                                        cartItems.length === 1 
                                        ? 'text-slate-300 cursor-not-allowed' 
                                        : 'text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20'
                                    }`}
                                >
                                    <Trash2 size={16} />
                                </button>
                            </div>
                        </div>

                        {/* Second Row: Price & Quantity */}
                        <div className="flex gap-2">
                             <div className="flex-1">
                                <label className="text-[10px] text-slate-400 font-bold uppercase mb-0.5 block">
                                    {type === 'LPO' ? 'Unit Cost (Ksh)' : 'Price (Ksh)'}
                                </label>
                                <input 
                                    type="number" 
                                    min="0"
                                    value={cartItem.price}
                                    onChange={(e) => handleItemChange(index, 'price', parseFloat(e.target.value) || 0)}
                                    className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm py-2 px-2"
                                />
                            </div>
                            <div className="w-24">
                                <label className="text-[10px] text-slate-400 font-bold uppercase mb-0.5 block">Qty</label>
                                <input 
                                    type="number" 
                                    min="1"
                                    value={cartItem.quantity}
                                    onChange={(e) => handleItemChange(index, 'quantity', parseInt(e.target.value) || 1)}
                                    className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm py-2 px-2 text-center"
                                />
                            </div>
                        </div>

                        {/* Third Row: Extra fields for New Items */}
                        {cartItem.isNew && (
                            <div className="grid grid-cols-3 gap-2 pt-1 animate-in slide-in-from-top-2 duration-200">
                                <div>
                                    <label className="text-[10px] text-blue-400 font-bold uppercase mb-0.5 block">Category</label>
                                    <select 
                                        value={cartItem.newItemData?.category}
                                        onChange={(e) => handleNewItemDataChange(index, 'category', e.target.value)}
                                        className="w-full rounded-lg border-blue-200 dark:border-blue-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-blue-500 focus:border-blue-500 text-xs py-1.5"
                                    >
                                        <option value="TOOLS">Tools</option>
                                        <option value="MATERIALS">Materials</option>
                                        <option value="PPE">PPE</option>
                                    </select>
                                </div>
                                <div>
                                    <label className="text-[10px] text-blue-400 font-bold uppercase mb-0.5 block">Unit</label>
                                    <input 
                                        type="text"
                                        placeholder="pcs, kg..." 
                                        value={cartItem.newItemData?.unit}
                                        onChange={(e) => handleNewItemDataChange(index, 'unit', e.target.value)}
                                        className="w-full rounded-lg border-blue-200 dark:border-blue-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-blue-500 focus:border-blue-500 text-xs py-1.5 px-2"
                                    />
                                </div>
                                <div>
                                    <label className="text-[10px] text-blue-400 font-bold uppercase mb-0.5 block">Selling Price</label>
                                    <input 
                                        type="number"
                                        min="0"
                                        value={cartItem.newItemData?.sellingPrice}
                                        onChange={(e) => handleNewItemDataChange(index, 'sellingPrice', parseFloat(e.target.value) || 0)}
                                        className="w-full rounded-lg border-blue-200 dark:border-blue-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-blue-500 focus:border-blue-500 text-xs py-1.5 px-2"
                                    />
                                </div>
                            </div>
                        )}
                    </div>
                 );
             })}

             <button 
                type="button"
                onClick={handleAddItem}
                className="w-full py-2 border-2 border-dashed border-slate-200 dark:border-slate-700 rounded-lg text-slate-500 dark:text-slate-400 text-xs font-bold uppercase tracking-wide hover:border-primary hover:text-primary transition-all flex items-center justify-center gap-2"
             >
                <Plus size={14} />
                Add Another Item
             </button>
          </div>

          <div className="flex justify-between items-center p-3 bg-slate-100 dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700">
            <span className="text-sm font-bold text-slate-500 uppercase">
                {type === 'DELIVERY' || type === 'LPO' ? 'Total Cost' : 'Grand Total'}
            </span>
            <span className="text-xl font-black text-slate-900 dark:text-white">{formatKsh(grandTotal)}</span>
          </div>

          {/* LPO Specifics */}
          {type === 'LPO' && (
             <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <Building2 size={12} /> Supplier Name <span className="text-red-500">*</span>
                    </label>
                    <input 
                      type="text" 
                      placeholder="e.g. Apex Cement Distributors Ltd"
                      value={supplierName}
                      onChange={(e) => setSupplierName(e.target.value)}
                      className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                    />
                 </div>
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <Calendar size={12} /> Expected Delivery Date (Optional)
                    </label>
                    <input 
                      type="date" 
                      value={expectedDate}
                      onChange={(e) => setExpectedDate(e.target.value)}
                      className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                    />
                 </div>
             </div>
          )}

          {/* Delivery Specifics */}
          {type === 'DELIVERY' && (
            <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                <div className="flex gap-4">
                    <div className="flex-1">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Clock size={12} /> Time Received
                        </label>
                        <input 
                        type="time" 
                        value={timeReceived}
                        onChange={(e) => setTimeReceived(e.target.value)}
                        className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                    <div className="flex-1">
                         <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <FileText size={12} /> PO Number
                        </label>
                        <input 
                        type="text" 
                        placeholder="PO-2023-001"
                        value={poNumber}
                        onChange={(e) => setPoNumber(e.target.value)}
                        className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <User size={12} /> Driver Name
                        </label>
                        <input 
                          type="text" 
                          placeholder="John Doe"
                          value={driverName}
                          onChange={(e) => setDriverName(e.target.value)}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Car size={12} /> Plate Number
                        </label>
                        <input 
                          type="text" 
                          placeholder="ABC 1234"
                          value={plateNumber}
                          onChange={(e) => setPlateNumber(e.target.value)}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                        />
                    </div>
                </div>
            </div>
          )}

          {/* Sale Specifics (Payment) */}
          {type === 'SALE' && (
            <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <User size={12} /> Customer Name (Optional)
                    </label>
                    <input 
                      type="text" 
                      placeholder="e.g. Walk-in or Company Name"
                      value={customerName}
                      onChange={(e) => setCustomerName(e.target.value)}
                      className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
                    />
                 </div>

                 <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                        <CreditCard size={12} /> Payment Method <span className="text-red-500">*</span>
                    </label>
                    <div className="flex gap-2">
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('CASH')}
                            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg border text-sm font-bold transition-all ${
                                paymentMethod === 'CASH' 
                                ? 'bg-emerald-500 text-white border-emerald-600 shadow-sm' 
                                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700'
                            }`}
                        >
                            <Banknote size={16} />
                            Cash
                        </button>
                        <button
                            type="button"
                            onClick={() => setPaymentMethod('MPESA')}
                            className={`flex-1 flex items-center justify-center gap-2 py-2.5 rounded-lg border text-sm font-bold transition-all ${
                                paymentMethod === 'MPESA' 
                                ? 'bg-emerald-500 text-white border-emerald-600 shadow-sm' 
                                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700'
                            }`}
                        >
                            <Smartphone size={16} />
                            M-Pesa
                        </button>
                    </div>
                 </div>

                 {paymentMethod === 'MPESA' && (
                     <div className="animate-in fade-in slide-in-from-top-1 duration-200">
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 flex items-center gap-1">
                            <Receipt size={12} /> Transaction Code <span className="text-red-500">*</span>
                        </label>
                        <input 
                          type="text" 
                          required={paymentMethod === 'MPESA'}
                          placeholder="e.g. QEH83729"
                          value={mpesaCode}
                          onChange={(e) => setMpesaCode(e.target.value.toUpperCase())}
                          className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm uppercase font-mono"
                        />
                     </div>
                 )}
            </div>
          )}

          <div>
            <label className="block text-xs font-bold text-slate-500 uppercase tracking-wide mb-2">
                {type === 'DELIVERY' ? 'Additional Notes' : type === 'LPO' ? 'Order Notes' : 'Notes / Remarks'}
            </label>
            <textarea 
              rows={2}
              value={notes}
              onChange={(e) => setNotes(e.target.value)}
              placeholder={type === 'SALE' ? "Additional sale info..." : type === 'RETURN' ? "e.g., Damaged item" : "Optional notes..."}
              className="w-full rounded-lg border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-primary focus:border-primary text-sm"
            ></textarea>
          </div>

          {/* Log/Receipt Preview Section */}
          {(type === 'DELIVERY' || type === 'SALE' || type === 'LPO') && previewText && (
            <div className="mt-2 p-3 bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 rounded-lg animate-in fade-in slide-in-from-top-2 duration-300">
               <div className="flex items-center gap-2 mb-1.5">
                 {type === 'SALE' ? <CreditCard size={12} className="text-blue-500"/> : <Eye size={12} className="text-blue-500" />}
                 <p className="text-[10px] font-bold text-blue-500 uppercase tracking-wide">
                    {type === 'SALE' ? 'Sale Summary' : type === 'LPO' ? 'Order Preview' : 'Log Preview'}
                 </p>
               </div>
               <div className="text-sm text-slate-700 dark:text-slate-300 font-mono whitespace-pre-wrap pl-5 border-l-2 border-blue-200 dark:border-blue-800">
                 {previewText}
               </div>
            </div>
          )}

          <div className="flex justify-end gap-3 pt-4 border-t border-slate-100 dark:border-slate-800 mt-2 shrink-0">
            <button 
              type="button" 
              onClick={onClose}
              className="px-4 py-2 text-sm font-medium text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white transition-colors"
            >
              Cancel
            </button>
            <button 
              type="submit"
              className="flex items-center gap-2 px-4 py-2 bg-primary text-white rounded-lg text-sm font-bold hover:bg-primary-dark transition-colors shadow-lg shadow-primary/20"
            >
              <Save size={16} />
              Confirm {type === 'SALE' ? 'Sale' : type === 'LPO' ? 'Order' : 'Action'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default ActionModal;

