      {/* Return Preview Modal */}
      <ReturnPreviewModal
        isOpen={returnPreviewState.isOpen}
        data={returnPreviewState.data}
        onClose={() => setReturnPreviewState({ isOpen: false, data: null })}
      />
    </div>
  );
}

export default App;

import { InventoryItem, ActivityItem } from './types';

export const INVENTORY_DATA: InventoryItem[] = [];

export const RECENT_ACTIVITY: ActivityItem[] = [];

import { openDB, DBSchema } from 'idb';
import { InventoryItem, ActivityItem, LPO, DailyStats } from './types';
import { INVENTORY_DATA } from './constants';

interface RingaDB extends DBSchema {
  inventory: {
    key: string;
    value: InventoryItem;
  };
  activities: {
    key: string;
    value: ActivityItem;
  };
  lpos: {
    key: string;
    value: LPO;
  };
  stats: {
    key: string;
    value: DailyStats & { id: string };
  };
}

// Changed to v2 to ensure a fresh start for the user
const DB_NAME = 'ringa-hardware-v2';
const DB_VERSION = 1;

export const initDB = async () => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION, {
    upgrade(db) {
      if (!db.objectStoreNames.contains('inventory')) {
        db.createObjectStore('inventory', { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains('activities')) {
        db.createObjectStore('activities', { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains('lpos')) {
        db.createObjectStore('lpos', { keyPath: 'id' });
      }
      if (!db.objectStoreNames.contains('stats')) {
        db.createObjectStore('stats', { keyPath: 'id' });
      }
    },
  });

  // Seed Data if empty
  const invCount = await db.count('inventory');
  if (invCount === 0 && INVENTORY_DATA.length > 0) {
    const tx = db.transaction('inventory', 'readwrite');
    for (const item of INVENTORY_DATA) {
      await tx.store.put(item);
    }
    await tx.done;
  }

  // Seed Stats if empty
  const stats = await db.get('stats', 'daily');
  if (!stats) {
    await db.put('stats', {
        id: 'daily',
        revenue: 0,
        profit: 0,
        transactionCount: 0
    });
  }

  return db;
};

// --- DATA FETCHING HELPERS ---

export const getInventory = async () => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
  return db.getAll('inventory');
};

export const getActivities = async () => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
  const acts = await db.getAll('activities');
  // Sort by ID (timestamp) descending
  return acts.sort((a, b) => Number(b.id) - Number(a.id));
};

export const getLPOs = async () => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
  const lpos = await db.getAll('lpos');
  return lpos.sort((a, b) => Number(b.id) - Number(a.id));
};

export const getStats = async () => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
  const stats = await db.get('stats', 'daily');
  return stats || { id: 'daily', revenue: 0, profit: 0, transactionCount: 0 };
};

export const getAllData = async () => {
    await initDB();
    const [inventory, activities, lpos, stats] = await Promise.all([
        getInventory(),
        getActivities(),
        getLPOs(),
        getStats()
    ]);
    return { inventory, activities, lpos, stats };
};

// --- CRUD OPERATIONS ---

export const updateInventoryItem = async (item: InventoryItem) => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
  return db.put('inventory', item);
};

export const addInventoryItem = async (item: InventoryItem) => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
  return db.put('inventory', item);
};

export const addActivity = async (activity: ActivityItem) => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
  return db.add('activities', activity);
};

export const addLPO = async (lpo: LPO) => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
  return db.add('lpos', lpo);
};

export const updateLPO = async (lpo: LPO) => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
  return db.put('lpos', lpo);
};

export const updateStats = async (stats: DailyStats) => {
  const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
  return db.put('stats', { ...stats, id: 'daily' });
};

// Batch update for inventory
export const updateInventoryBatch = async (items: InventoryItem[]) => {
    const db = await openDB<RingaDB>(DB_NAME, DB_VERSION);
    const tx = db.transaction('inventory', 'readwrite');
    await Promise.all([...items.map(item => tx.store.put(item))]);
    await tx.done;
};

import React, { useState, useEffect } from 'react';
import { X, Save, FileText, User, Car, Clock, Eye, Layers, Package, Wrench, HardHat, CreditCard, Banknote, Smartphone, Plus, Trash2, Building2, Calendar, PackagePlus, ArrowLeft, Receipt, Percent, Tag } from 'lucide-react';
import { InventoryItem } from '../types';

interface ActionModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSubmit: (items: { itemId: string; quantity: number; price: number }[], notes: string, meta?: any) => void;
  type: 'DELIVERY' | 'SALE' | 'RETURN' | 'LPO' | null;
  inventory: InventoryItem[];
}

interface CartItem {
  itemId: string;
  quantity: number;
  price: number;
  isNew?: boolean;
  newItemData?: {
      name: string;
      category: 'TOOLS' | 'MATERIALS' | 'PPE';
      unit: string;
      sellingPrice: number;
  };
}

const ActionModal: React.FC<ActionModalProps> = ({ isOpen, onClose, onSubmit, type, inventory }) => {
  // State for multiple items
  const [cartItems, setCartItems] = useState<CartItem[]>([{ itemId: '', quantity: 1, price: 0 }]);

  const [notes, setNotes] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  // Delivery specific fields
  const [poNumber, setPoNumber] = useState('');
  const [driverName, setDriverName] = useState('');
  const [plateNumber, setPlateNumber] = useState('');
  const [timeReceived, setTimeReceived] = useState('');

  // Sale specific fields
  const [customerName, setCustomerName] = useState('');
  const [paymentMethod, setPaymentMethod] = useState<'CASH' | 'MPESA'>('CASH');
  const [mpesaCode, setMpesaCode] = useState('');

  // Discount Fields
  const [discountValue, setDiscountValue] = useState<number>(0);
  const [discountType, setDiscountType] = useState<'PERCENTAGE' | 'FIXED'>('PERCENTAGE');

  // LPO Specific fields
  const [supplierName, setSupplierName] = useState('');
  const [expectedDate, setExpectedDate] = useState('');

  // Filter inventory for the dropdowns
  const filteredInventory = inventory.filter(item => 
    activeCategory === 'ALL' ? true : item.category === activeCategory
  );

  // Helper to format currency
  const formatKsh = (amount: number) => {
    return `Ksh ${amount.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 0 })}`;
  };

  // Helper to get active price based on transaction type
  const getTransactionPrice = (item: InventoryItem) => {
    // If we are Buying (Delivery) or Ordering (LPO), use Buying Price (Cost)
    if (type === 'DELIVERY' || type === 'LPO') return item.buyingPrice;
    return item.sellingPrice; // SALE or RETURN
  };

  // Calculate Subtotal (Sum of items)
  const calculateSubtotal = () => {
    return cartItems.reduce((sum, cartItem) => {
      return sum + (cartItem.price * cartItem.quantity);
    }, 0);
  };

  // Calculate Final Grand Total (Subtract Discount)
  const subtotal = calculateSubtotal();

  let discountAmount = 0;
  if (type === 'SALE') {
    if (discountType === 'PERCENTAGE') {
        discountAmount = subtotal * (discountValue / 100);
    } else {
        discountAmount = discountValue;
    }
  }

  // Ensure we don't go below zero
  const grandTotal = Math.max(0, subtotal - discountAmount);

  // Reset form when modal opens
  useEffect(() => {
    if (isOpen) {
      setActiveCategory('ALL');

      // Initialize with first available item and its price
      const defaultItem = inventory[0];
      const defaultPrice = defaultItem ? getTransactionPrice(defaultItem) : 0;

      setCartItems([{ 
        itemId: defaultItem?.id || '', 
        quantity: 1, 
        price: defaultPrice,
        isNew: false 
      }]);

      setNotes('');
      setPoNumber('');
      setDriverName('');
      setPlateNumber('');
      setCustomerName('');
      setPaymentMethod('CASH');
      setMpesaCode('');
      setSupplierName('');
      setExpectedDate('');
      setDiscountValue(0);
      setDiscountType('PERCENTAGE');

      const now = new Date();
      setTimeReceived(`${String(now.getHours()).padStart(2, '0')}:${String(now.getMinutes()).padStart(2, '0')}`);
    }
  }, [isOpen, inventory, type]);

  // --- Item Management Handlers ---

  const handleAddItem = () => {
    // Add new row with first available item in current filter
    const defaultItem = filteredInventory[0] || inventory[0];
    const defaultId = defaultItem?.id || '';
    const defaultPrice = defaultItem ? getTransactionPrice(defaultItem) : 0;

    setCartItems([...cartItems, { itemId: defaultId, quantity: 1, price: defaultPrice, isNew: false }]);
  };

  const handleRemoveItem = (index: number) => {
    if (cartItems.length > 1) {
      const newItems = [...cartItems];
      newItems.splice(index, 1);
      setCartItems(newItems);
    }
  };

  const handleItemChange = (index: number, field: keyof CartItem, value: any) => {
    const newItems = [...cartItems];

    if (field === 'itemId') {
      // When item changes, also update the price default
      const item = inventory.find(i => i.id === value);
      const newPrice = item ? getTransactionPrice(item) : 0;
      newItems[index] = { 
        ...newItems[index], 
        itemId: String(value), 
        price: newPrice 
      };
    } else {
      // @ts-ignore
      newItems[index] = { ...newItems[index], [field]: value };
    }

    setCartItems(newItems);
  };

  const handleNewItemDataChange = (index: number, field: string, value: any) => {
    const newItems = [...cartItems];
    if (newItems[index].newItemData) {
        newItems[index].newItemData = { ...newItems[index].newItemData!, [field]: value };
        setCartItems(newItems);
    }
  };

  const toggleNewItemMode = (index: number) => {
    const newItems = [...cartItems];
    const current = newItems[index];

    if (!current.isNew) {
        // Switch TO new item mode
        newItems[index] = {
            ...current,
            itemId: `NEW_${Date.now()}_${index}`, // Temp ID
            isNew: true,
            newItemData: { 
                name: '', 
                category: 'TOOLS', 
                unit: 'pcs', 
                sellingPrice: 0 
            },
            price: 0 // Reset cost to 0 for user to input
        };
    } else {
        // Switch BACK to existing item mode
        const defaultItem = filteredInventory[0] || inventory[0];
        newItems[index] = {
            ...current,
            itemId: defaultItem?.id || '',
            isNew: false,
            newItemData: undefined,
            price: defaultItem ? getTransactionPrice(defaultItem) : 0
        };
    }
    setCartItems(newItems);
  };

  // --- Preview Logic ---

  const getPreviewText = () => {
    const itemCount = cartItems.length;
    const itemSummary = cartItems.map(c => {
        if (c.isNew && c.newItemData) {
            return `${c.newItemData.name} (New) (x${c.quantity})`;
        }
        const i = inventory.find(inv => inv.id === c.itemId);
        return i ? `${i.name} (x${c.quantity})` : 'Unknown';
    }).join(', ');

    if (type === 'DELIVERY') {
        const details = [
            `Items (${itemCount}): ${itemSummary}`,
            poNumber && `PO: ${poNumber}`,
            driverName && `Driver: ${driverName}`,
            plateNumber && `Plate: ${plateNumber}`,
            timeReceived && `Time: ${timeReceived}`,
            `Total Cost: ${formatKsh(grandTotal)}`
        ].filter(Boolean).join(' • ');
        return notes ? `${details} \nNote: ${notes}` : details;
    } else if (type === 'SALE') {
        const paymentDetails = paymentMethod === 'CASH' ? 'Cash' : `M-Pesa: ${mpesaCode}`;
        const discountText = discountAmount > 0 ? ` (Disc: -${formatKsh(discountAmount)})` : '';
        const details = [
            `Items: ${itemSummary}`,
            customerName && `Customer: ${customerName}`,
            `Payment: ${paymentDetails}`,
            `Total: ${formatKsh(grandTotal)}${discountText}`
        ].filter(Boolean).join(' • ');
        return notes ? `${details} \nNote: ${notes}` : details;
    } else if (type === 'LPO') {
       const details = [
            `Supplier: ${supplierName || 'N/A'}`,
            `Items: ${itemSummary}`,
            `Est. Cost: ${formatKsh(grandTotal)}`,
            expectedDate && `Expected: ${expectedDate}`
       ].filter(Boolean).join(' • ');
       return notes ? `${details} \nNote: ${notes}` : details;
    }
    return notes;
  };

  const previewText = getPreviewText();

  if (!isOpen || !type) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Validate fields
    if (type === 'SALE' && paymentMethod === 'MPESA' && !mpesaCode.trim()) {
        return; 
    }

    if (type === 'LPO' && !supplierName.trim()) {
        alert("Please enter a Supplier Name");
        return;
    }

    // Validate new items
    for (const item of cartItems) {
        if (item.isNew) {
            if (!item.newItemData?.name.trim()) {
                alert("Please enter a name for the new item.");
                return;
            }
        } else if (!item.itemId) {
            // Filter out empty existing items if any
            continue;
        }
    }

    const validItems = cartItems.filter(i => i.itemId);
    if (validItems.length === 0) return;

    let submissionNotes = notes;
    let metaData: any = {};
    const newItemsDefinitions = cartItems
        .filter(i => i.isNew && i.newItemData)
        .map(i => ({
            tempId: i.itemId,
            ...i.newItemData,
            buyingPrice: i.price // Current price input is the buying cost
        }));

    if (type === 'DELIVERY') {
      submissionNotes = getPreviewText();
      metaData = {
          newItemsDefinitions
      };
    } else if (type === 'SALE') {
      const paymentDetails = paymentMethod === 'CASH' ? 'Cash' : `M-Pesa: ${mpesaCode}`;
      const discountInfo = discountAmount > 0 ? `With ${formatKsh(discountAmount)} discount. ` : '';
      submissionNotes = `${customerName ? `Cust: ${customerName}` : 'Walk-in'} • ${paymentDetails} • Total: ${formatKsh(grandTotal)}`;
      if (notes) submissionNotes += ` • ${notes}`;

      metaData = {
        customerName,
        paymentMethod,
        mpesaCode,
        totalPrice: grandTotal,
        subtotal: subtotal,
        discount: discountAmount
      };
    } else if (type === 'LPO') {
      submissionNotes = getPreviewText();
      metaData = {
        supplierName,
        expectedDate,
        totalExpectedCost: grandTotal,
        newItemsDefinitions: newItemsDefinitions
      };
    }

    onSubmit(validItems, submissionNotes, metaData);
    onClose();
  };

  const getTitle = () => {
    switch(type) {
      case 'DELIVERY': return 'Log Incoming Delivery';
      case 'SALE': return 'Record New Sale';
      case 'RETURN': return 'Log Customer Return';
      case 'LPO': return 'Create Purchase Order (LPO)';
      default: return '';
    }
